import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { createPortal } from 'react-dom';
import Icon from './common/Icon';
import { Link } from 'react-router-dom';
import { AddToInvestigationButton } from './common/AddToInvestigationButton';

import { RouteMap } from './visualizations/RouteMap';
import { Select } from './common/Select';

import './FlightTracker.css';

interface Flight {
  id: number;
  date: string;
  departure_airport: string;
  departure_city: string;
  departure_country: string;
  arrival_airport: string;
  arrival_city: string;
  arrival_country: string;
  aircraft_tail: string;
  aircraft_type: string;
  passengers?: { passenger_name: string; role: string; entity_id?: number }[];
}

interface FlightStats {
  totalFlights: number;
  uniquePassengers: number;
  topPassengers: { name: string; count: number }[];
  topRoutes: { route: string; count: number }[];
  flightsByYear: { year: string; count: number }[];
  airports: { code: string; city: string; count: number }[];
}

interface AirportCoords {
  [code: string]: { lat: number; lng: number; city: string };
}

type ViewMode = 'timeline' | 'map' | 'stats' | 'network';

interface CoOccurrence {
  passenger1: string;
  passenger2: string;
  flights_together: number;
  entity_id1?: number;
  entity_id2?: number;
}

const FlightTracker: React.FC = () => {
  const [flights, setFlights] = useState<Flight[]>([]);
  const [stats, setStats] = useState<FlightStats | null>(null);
  const [airports, setAirports] = useState<AirportCoords>({});
  const [loading, setLoading] = useState(true);
  const [viewMode, setViewMode] = useState<ViewMode>('timeline');
  const [selectedPassenger, setSelectedPassenger] = useState<string>('');
  const [dateRange, setDateRange] = useState({ start: '', end: '' });
  const [passengers, setPassengers] = useState<{ name: string; flight_count: number }[]>([]);
  const [selectedFlight, setSelectedFlight] = useState<Flight | null>(null);
  const [coOccurrences, setCoOccurrences] = useState<CoOccurrence[]>([]);
  const [networkLoading, setNetworkLoading] = useState(false);

  const loadData = useCallback(async () => {
    setLoading(true);
    try {
      const params = new URLSearchParams();
      if (selectedPassenger) params.append('passenger', selectedPassenger);
      if (dateRange.start) params.append('startDate', dateRange.start);
      if (dateRange.end) params.append('endDate', dateRange.end);
      params.append('limit', '100');

      const [flightsRes, statsRes, airportsRes, passengersRes] = await Promise.all([
        fetch(`/api/flights?${params}`),
        fetch('/api/flights/stats'),
        fetch('/api/flights/airports'),
        fetch('/api/flights/passengers'),
      ]);

      const flightsData = await flightsRes.json();
      const statsData = await statsRes.json();
      const airportsData = await airportsRes.json();
      const passengersData = await passengersRes.json();

      setFlights(flightsData.flights || []);
      setStats(statsData);
      setAirports(airportsData);
      // Ensure passengersData is an array
      setPassengers(
        Array.isArray(passengersData) ? passengersData : passengersData.passengers || [],
      );
    } catch (error) {
      console.error('Failed to load flight data:', error);
    } finally {
      setLoading(false);
    }
  }, [selectedPassenger, dateRange.start, dateRange.end]);

  useEffect(() => {
    loadData();
  }, [loadData]);

  const loadCoOccurrences = async () => {
    setNetworkLoading(true);
    try {
      const res = await fetch('/api/flights/co-occurrences?minFlights=2&limit=100');
      const data = await res.json();
      setCoOccurrences(data || []);
    } catch (error) {
      console.error('Failed to load co-occurrences:', error);
    } finally {
      setNetworkLoading(false);
    }
  };

  useEffect(() => {
    if (viewMode === 'network' && coOccurrences.length === 0) {
      loadCoOccurrences();
    }
  }, [viewMode]);

  const formatDate = (dateStr: string) => {
    const date = new Date(dateStr);
    return date.toLocaleDateString('en-US', {
      weekday: 'short',
      year: 'numeric',
      month: 'short',
      day: 'numeric',
    });
  };

  // Simple SVG world map with flight routes
  const MapView = () => {
    const uniqueRoutes = useMemo(() => {
      const routeMap = new Map<string, number>();
      flights.forEach((f) => {
        const key = `${f.departure_airport}-${f.arrival_airport}`;
        routeMap.set(key, (routeMap.get(key) || 0) + 1);
      });
      return Array.from(routeMap.entries()).map(([key, count]) => {
        const [from, to] = key.split('-');
        return { from, to, count };
      });
    }, [flights]);

    // Convert lat/lng to SVG coordinates (simple Mercator-like projection)
    const toSvgCoords = (lat: number, lng: number) => {
      const x = ((lng + 180) / 360) * 800;
      const y = ((90 - lat) / 180) * 400;
      return { x, y };
    };

    return (
      <div className="flight-map-container">
        <svg viewBox="0 0 800 400" className="flight-map">
          {/* Simple world background */}
          <rect x="0" y="0" width="800" height="400" fill="#0a0a1a" />

          {/* Grid lines */}
          {[...Array(9)].map((_, i) => (
            <line
              key={`h${i}`}
              x1="0"
              y1={i * 50}
              x2="800"
              y2={i * 50}
              stroke="#1a1a2e"
              strokeWidth="0.5"
            />
          ))}
          {[...Array(17)].map((_, i) => (
            <line
              key={`v${i}`}
              x1={i * 50}
              y1="0"
              x2={i * 50}
              y2="400"
              stroke="#1a1a2e"
              strokeWidth="0.5"
            />
          ))}

          {/* Draw routes */}
          {uniqueRoutes.map((route, i) => {
            const fromCoords = airports[route.from];
            const toCoords = airports[route.to];
            if (!fromCoords || !toCoords) return null;

            const from = toSvgCoords(fromCoords.lat, fromCoords.lng);
            const to = toSvgCoords(toCoords.lat, toCoords.lng);

            // Calculate control point for curved line
            const midX = (from.x + to.x) / 2;
            const midY = (from.y + to.y) / 2 - 30;

            return (
              <g key={i}>
                <path
                  d={`M ${from.x} ${from.y} Q ${midX} ${midY} ${to.x} ${to.y}`}
                  fill="none"
                  stroke={`rgba(0, 200, 255, ${Math.min(0.3 + route.count * 0.1, 0.9)})`}
                  strokeWidth={Math.min(1 + route.count * 0.3, 3)}
                  strokeDasharray="5,3"
                  className="flight-route"
                />
              </g>
            );
          })}

          {/* Draw airports */}
          {Object.entries(airports).map(([code, coords]) => {
            const { x, y } = toSvgCoords(coords.lat, coords.lng);
            const flightCount = stats?.airports.find((a) => a.code === code)?.count || 0;

            return (
              <g key={code} className="airport-marker">
                <circle
                  cx={x}
                  cy={y}
                  r={Math.min(4 + flightCount * 0.3, 10)}
                  fill="#00c8ff"
                  opacity="0.8"
                />
                <circle
                  cx={x}
                  cy={y}
                  r={Math.min(4 + flightCount * 0.3, 10)}
                  fill="none"
                  stroke="#00c8ff"
                  strokeWidth="2"
                  className="airport-pulse"
                />
                <text
                  x={x}
                  y={y - 12}
                  fill="#fff"
                  fontSize="8"
                  textAnchor="middle"
                  className="airport-label"
                >
                  {code}
                </text>
              </g>
            );
          })}
        </svg>

        <div className="map-legend">
          <h4>Key Locations</h4>
          <div className="legend-items">
            <div className="legend-item">
              <span className="legend-dot primary" /> Primary Hubs
            </div>
            <div className="legend-item">
              <span className="legend-dot secondary" /> Destinations
            </div>
          </div>
        </div>
      </div>
    );
  };

  // Timeline view
  const TimelineView = () => (
    <div className="flight-timeline">
      {flights.map((flight, _index) => (
        <div key={flight.id} className="flight-card" onClick={() => setSelectedFlight(flight)}>
          <div className="flight-date">
            <span className="date-badge">{formatDate(flight.date)}</span>
          </div>

          <div className="flight-route">
            <div className="airport departure">
              <span className="airport-code">{flight.departure_airport}</span>
              <span className="airport-city">{flight.departure_city}</span>
            </div>

            <div className="flight-line">
              <div className="plane-icon">✈</div>
              <div className="dashed-line" />
            </div>

            <div className="airport arrival">
              <span className="airport-code">{flight.arrival_airport}</span>
              <span className="airport-city">{flight.arrival_city}</span>
            </div>
          </div>

          <div className="flight-passengers">
            <span className="passenger-count">
              <Icon name="Users" size="sm" /> {flight.passengers?.length || 0} passengers
            </span>
            <div className="passenger-names">
              {flight.passengers?.slice(0, 3).map((p, i) => (
                <span key={i} className={`passenger-tag ${p.role}`}>
                  {p.passenger_name}
                </span>
              ))}
              {(flight.passengers?.length || 0) > 3 && (
                <span className="more-passengers">
                  +{(flight.passengers?.length || 0) - 3} more
                </span>
              )}
            </div>
          </div>

          <div className="flight-aircraft">
            <span className="tail-number">{flight.aircraft_tail}</span>
            <span className="aircraft-type">{flight.aircraft_type}</span>
          </div>
        </div>
      ))}
    </div>
  );

  // Network/Co-occurrence view
  const NetworkView = () => {
    // Build nodes from unique passengers
    const nodes = useMemo(() => {
      const nodeMap = new Map<string, { name: string; connections: number; entityId?: number }>();
      coOccurrences.forEach((co) => {
        if (!nodeMap.has(co.passenger1)) {
          nodeMap.set(co.passenger1, {
            name: co.passenger1,
            connections: 0,
            entityId: co.entity_id1,
          });
        }
        if (!nodeMap.has(co.passenger2)) {
          nodeMap.set(co.passenger2, {
            name: co.passenger2,
            connections: 0,
            entityId: co.entity_id2,
          });
        }
        nodeMap.get(co.passenger1)!.connections += co.flights_together;
        nodeMap.get(co.passenger2)!.connections += co.flights_together;
      });
      return Array.from(nodeMap.values()).sort((a, b) => b.connections - a.connections);
    }, [coOccurrences]);

    // Top connections for the selected view
    const topConnections = useMemo(() => {
      return coOccurrences.slice(0, 30);
    }, [coOccurrences]);

    if (networkLoading) {
      return (
        <div className="loading-state">
          <div className="loading-spinner">
            <div className="radar-sweep" />
            <span>Analyzing passenger connections...</span>
          </div>
        </div>
      );
    }

    return (
      <div className="network-view">
        <div className="network-header">
          <h3>
            <Icon name="Users" size="sm" /> Passenger Co-Occurrence Network
          </h3>
          <p className="network-description">
            Shows which passengers frequently flew together. Stronger connections indicate more
            shared flights.
          </p>
        </div>

        {/* Top Co-Travelers */}
        <div className="co-occurrence-list">
          <h4>Top Co-Travelers</h4>
          <div className="co-occurrence-grid">
            {topConnections.map((co, i) => (
              <div key={i} className="co-occurrence-card">
                <div className="co-passengers">
                  <span className="passenger-name">
                    {co.entity_id1 ? (
                      <Link to={`/entity/${co.entity_id1}`}>{co.passenger1}</Link>
                    ) : (
                      co.passenger1
                    )}
                  </span>
                  <span className="connection-indicator">
                    <Icon name="Link" size="sm" />
                    <span className="flight-count">{co.flights_together}</span>
                  </span>
                  <span className="passenger-name">
                    {co.entity_id2 ? (
                      <Link to={`/entity/${co.entity_id2}`}>{co.passenger2}</Link>
                    ) : (
                      co.passenger2
                    )}
                  </span>
                </div>
                <div className="connection-bar">
                  <div
                    className="connection-fill"
                    style={{
                      width: `${Math.min((co.flights_together / (topConnections[0]?.flights_together || 1)) * 100, 100)}%`,
                    }}
                  />
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Most Connected Passengers */}
        <div className="connected-passengers">
          <h4>Most Connected Passengers</h4>
          <div className="passenger-connections-grid">
            {nodes.slice(0, 15).map((node, i) => (
              <div key={i} className="passenger-connection-card">
                <span className="rank">#{i + 1}</span>
                <span className="name">
                  {node.entityId ? (
                    <Link to={`/entity/${node.entityId}`}>{node.name}</Link>
                  ) : (
                    node.name
                  )}
                </span>
                <span className="connection-count">{node.connections} shared flights</span>
              </div>
            ))}
          </div>
        </div>

        <style>{`
          .network-view {
            padding: 20px;
          }
          .network-header {
            margin-bottom: 24px;
          }
          .network-header h3 {
            display: flex;
            align-items: center;
            gap: 8px;
            margin: 0 0 8px 0;
          }
          .network-description {
            color: #888;
            margin: 0;
          }
          .co-occurrence-list, .connected-passengers {
            background: #1a1a2e;
            border: 1px solid #2a2a4a;
            border-radius: 12px;
            padding: 20px;
            margin-bottom: 20px;
          }
          .co-occurrence-list h4, .connected-passengers h4 {
            margin: 0 0 16px 0;
            font-size: 1rem;
          }
          .co-occurrence-grid {
            display: flex;
            flex-direction: column;
            gap: 12px;
          }
          .co-occurrence-card {
            background: #0a0a1a;
            border-radius: 8px;
            padding: 12px 16px;
          }
          .co-passengers {
            display: flex;
            align-items: center;
            gap: 12px;
            margin-bottom: 8px;
          }
          .passenger-name {
            flex: 1;
          }
          .passenger-name a {
            color: #6366f1;
            text-decoration: none;
          }
          .passenger-name a:hover {
            text-decoration: underline;
          }
          .connection-indicator {
            display: flex;
            align-items: center;
            gap: 4px;
            color: #10b981;
            font-weight: 600;
          }
          .flight-count {
            background: #10b981;
            color: #000;
            padding: 2px 8px;
            border-radius: 12px;
            font-size: 0.85rem;
          }
          .connection-bar {
            height: 4px;
            background: #2a2a4a;
            border-radius: 2px;
            overflow: hidden;
          }
          .connection-fill {
            height: 100%;
            background: linear-gradient(90deg, #6366f1, #10b981);
            border-radius: 2px;
            transition: width 0.3s ease;
          }
          .passenger-connections-grid {
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(250px, 1fr));
            gap: 12px;
          }
          .passenger-connection-card {
            display: flex;
            align-items: center;
            gap: 12px;
            background: #0a0a1a;
            padding: 12px 16px;
            border-radius: 8px;
          }
          .passenger-connection-card .rank {
            font-weight: 700;
            color: #6366f1;
            min-width: 30px;
          }
          .passenger-connection-card .name {
            flex: 1;
          }
          .passenger-connection-card .name a {
            color: #6366f1;
            text-decoration: none;
          }
          .passenger-connection-card .connection-count {
            color: #888;
            font-size: 0.85rem;
          }
        `}</style>
      </div>
    );
  };

  // Stats view
  const StatsView = () => (
    <div className="flight-stats-grid">
      <div className="stat-card primary">
        <div className="stat-icon">✈</div>
        <div className="stat-value">{stats?.totalFlights || 0}</div>
        <div className="stat-label">Total Flights</div>
      </div>

      <div className="stat-card">
        <div className="stat-icon">👥</div>
        <div className="stat-value">{stats?.uniquePassengers || 0}</div>
        <div className="stat-label">Unique Passengers</div>
      </div>

      <div className="stat-card full-width">
        <h3>Top Passengers</h3>
        <div className="stat-bars">
          {stats?.topPassengers.slice(0, 8).map((p, i) => (
            <div key={i} className="stat-bar-item">
              <span className="bar-label">{p.name}</span>
              <div className="bar-track">
                <div
                  className="bar-fill"
                  style={{ width: `${(p.count / (stats.topPassengers[0]?.count || 1)) * 100}%` }}
                />
              </div>
              <span className="bar-value">{p.count}</span>
            </div>
          ))}
        </div>
      </div>

      <div className="stat-card">
        <h3>Top Routes</h3>
        <div className="route-list">
          {stats?.topRoutes.slice(0, 5).map((r, i) => (
            <div key={i} className="route-item">
              <span className="route-path">{r.route}</span>
              <span className="route-count">{r.count}x</span>
            </div>
          ))}
        </div>
      </div>

      <div className="stat-card">
        <h3>Flights by Year</h3>
        <div className="year-chart">
          {stats?.flightsByYear.map((y, i) => (
            <div key={i} className="year-bar">
              <div
                className="year-fill"
                style={{
                  height: `${(y.count / Math.max(...stats.flightsByYear.map((x) => x.count))) * 100}%`,
                }}
              />
              <span className="year-label">{y.year}</span>
              <span className="year-count">{y.count}</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );

  // Convert lat/lng to SVG coordinates for flight path map
  const _toSvgCoords = (lat: number, lng: number, width: number, height: number) => {
    const x = ((lng + 180) / 360) * width;
    const y = ((90 - lat) / 180) * height;
    return { x, y };
  };

  // Flight detail modal
  const FlightModal = () => {
    if (!selectedFlight) return null;

    return createPortal(
      <div className="flight-modal-overlay" onClick={() => setSelectedFlight(null)}>
        <div className="flight-modal" onClick={(e) => e.stopPropagation()}>
          <button className="modal-close" onClick={() => setSelectedFlight(null)}>
            ×
          </button>

          <div className="modal-header" style={{ paddingRight: '3rem' }}>
            <h2>Flight Details</h2>
            <span className="flight-date">{formatDate(selectedFlight.date)}</span>
          </div>

          {/* Flight Route Map & Info */}
          {(() => {
            const departureCoords = airports[selectedFlight.departure_airport];
            const arrivalCoords = airports[selectedFlight.arrival_airport];
            return (
              <>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
                  <div className="bg-slate-800/50 p-4 rounded-lg border border-slate-700/50">
                    <div className="flex items-center gap-2 mb-2">
                      <Icon name="ArrowUpRight" className="text-blue-400" size="sm" />
                      <span className="text-sm font-medium text-slate-400">Departure</span>
                    </div>
                    <div className="text-lg font-bold text-white mb-1">
                      {selectedFlight.departure_airport}
                    </div>
                    <div className="text-sm text-slate-500">
                      {new Date(selectedFlight.date).toLocaleString()}
                    </div>
                  </div>

                  <div className="bg-slate-800/50 p-4 rounded-lg border border-slate-700/50">
                    <div className="flex items-center gap-2 mb-2">
                      <Icon name="ArrowDown" className="text-emerald-400" size="sm" />
                      <span className="text-sm font-medium text-slate-400">Arrival</span>
                    </div>
                    <div className="text-lg font-bold text-white mb-1">
                      {selectedFlight.arrival_airport}
                    </div>
                    <div className="text-sm text-slate-500">
                      {new Date(selectedFlight.date).toLocaleString()}
                    </div>
                  </div>
                </div>

                {/* Flight Route Map */}
                {(departureCoords || arrivalCoords) && (
                  <div className="mb-6">
                    <h4 className="text-sm font-medium text-slate-400 mb-3 flex items-center gap-2">
                      <Icon name="Globe" size="sm" />
                      Flight Path Visualization
                    </h4>
                    {departureCoords && arrivalCoords ? (
                      <RouteMap
                        departure={{
                          lat: departureCoords.lat,
                          lng: departureCoords.lng,
                          name: selectedFlight.departure_city || selectedFlight.departure_airport,
                          code: selectedFlight.departure_airport,
                        }}
                        arrival={{
                          lat: arrivalCoords.lat,
                          lng: arrivalCoords.lng,
                          name: selectedFlight.arrival_city || selectedFlight.arrival_airport,
                          code: selectedFlight.arrival_airport,
                        }}
                      />
                    ) : (
                      <div className="bg-slate-800/50 p-8 rounded-lg border border-slate-700/50 text-center">
                        <Icon name="MapPin" size="lg" className="text-slate-600 mb-2 mx-auto" />
                        <p className="text-slate-400">
                          Complete route data unavailable for map visualization
                        </p>
                      </div>
                    )}
                  </div>
                )}
              </>
            );
          })()}

          <div className="modal-route">
            <div className="route-endpoint">
              <span className="code">{selectedFlight.departure_airport}</span>
              <span className="city">{selectedFlight.departure_city}</span>
            </div>
            <div className="route-arrow">→</div>
            <div className="route-endpoint">
              <span className="code">{selectedFlight.arrival_airport}</span>
              <span className="city">{selectedFlight.arrival_city}</span>
            </div>
          </div>

          <div className="modal-section">
            <h3>Aircraft</h3>
            <p>
              {selectedFlight.aircraft_type} ({selectedFlight.aircraft_tail})
            </p>
          </div>

          <div className="modal-section">
            <h3>Passenger Manifest ({selectedFlight.passengers?.length || 0})</h3>
            <div className="passenger-list">
              {selectedFlight.passengers?.map((p, i) => (
                <div key={i} className="passenger-row">
                  <span className={`role-badge ${p.role}`}>{p.role}</span>
                  {p.entity_id ? (
                    <Link to={`/entity/${p.entity_id}`} className="passenger-link">
                      {p.passenger_name}
                    </Link>
                  ) : (
                    <span>{p.passenger_name}</span>
                  )}
                </div>
              ))}
            </div>
          </div>

          {/* Add to Investigation */}
          <div
            className="modal-section"
            style={{ borderTop: '1px solid #2a2a4a', paddingTop: '16px' }}
          >
            <AddToInvestigationButton
              item={{
                id: String(selectedFlight.id),
                title: `Flight ${selectedFlight.aircraft_tail}: ${selectedFlight.departure_airport} → ${selectedFlight.arrival_airport}`,
                description: `${formatDate(selectedFlight.date)} - ${selectedFlight.passengers?.length || 0} passengers including ${selectedFlight.passengers
                  ?.slice(0, 3)
                  .map((p) => p.passenger_name)
                  .join(
                    ', ',
                  )}${selectedFlight.passengers && selectedFlight.passengers.length > 3 ? '...' : ''}`,
                type: 'flight',
                sourceId: String(selectedFlight.id),
                metadata: {
                  date: selectedFlight.date,
                  departure: selectedFlight.departure_airport,
                  arrival: selectedFlight.arrival_airport,
                  aircraft: selectedFlight.aircraft_tail,
                  passengerCount: selectedFlight.passengers?.length || 0,
                },
              }}
              variant="button"
            />
          </div>
        </div>
      </div>,
      document.body,
    );
  };

  if (loading) {
    return (
      <div className="flight-tracker loading-state">
        <div className="loading-spinner">
          <div className="radar-sweep" />
          <span>Loading Flight Data...</span>
        </div>
      </div>
    );
  }

  return (
    <div className="flight-tracker">
      <div className="tracker-header">
        <div className="header-left">
          <h1>
            <Icon name="Navigation" size="lg" />
            Flight Tracker
          </h1>
          <p className="subtitle">Tracking flights on N908JE "Lolita Express"</p>
        </div>

        <div className="header-stats">
          <div className="mini-stat">
            <span className="value">{stats?.totalFlights || 0}</span>
            <span className="label">Flights</span>
          </div>
          <div className="mini-stat">
            <span className="value">{stats?.uniquePassengers || 0}</span>
            <span className="label">Passengers</span>
          </div>
          <div className="mini-stat">
            <span className="value">{Object.keys(airports).length}</span>
            <span className="label">Airports</span>
          </div>
        </div>
      </div>

      <div className="tracker-controls">
        <div className="view-toggle">
          <button
            className={viewMode === 'timeline' ? 'active' : ''}
            onClick={() => setViewMode('timeline')}
          >
            <Icon name="List" size="sm" /> Timeline
          </button>
          <button className={viewMode === 'map' ? 'active' : ''} onClick={() => setViewMode('map')}>
            <Icon name="Globe" size="sm" /> Map
          </button>
          <button
            className={viewMode === 'stats' ? 'active' : ''}
            onClick={() => setViewMode('stats')}
          >
            <Icon name="BarChart3" size="sm" /> Stats
          </button>
          <button
            className={viewMode === 'network' ? 'active' : ''}
            onClick={() => setViewMode('network')}
          >
            <Icon name="Users" size="sm" /> Network
          </button>
        </div>

        <div className="filters">
          <div className="flex flex-wrap gap-4">
            <Select
              containerClassName="min-w-[200px]"
              value={selectedPassenger}
              onChange={(e) => setSelectedPassenger(e.target.value)}
              options={[
                { value: '', label: 'All Passengers' },
                ...passengers.map((p) => ({
                  value: p.name,
                  label: `${p.name} (${p.flight_count})`,
                })),
              ]}
            />

            <div className="flex items-center gap-2 bg-slate-900/50 border border-slate-700 rounded-lg px-3 py-2">
              <Icon name="Calendar" size="sm" className="text-slate-400" />
              <input
                type="date"
                value={dateRange.start}
                onChange={(e) => setDateRange({ ...dateRange, start: e.target.value })}
                className="bg-transparent border-none text-white text-sm focus:outline-none"
                placeholder="Start Date"
              />
              <span className="text-slate-500">-</span>
              <input
                type="date"
                value={dateRange.end}
                onChange={(e) => setDateRange({ ...dateRange, end: e.target.value })}
                className="bg-transparent border-none text-white text-sm focus:outline-none"
                placeholder="End Date"
              />
            </div>
          </div>
        </div>
      </div>

      <div className="tracker-content">
        {viewMode === 'timeline' && <TimelineView />}
        {viewMode === 'map' && <MapView />}
        {viewMode === 'stats' && <StatsView />}
        {viewMode === 'network' && <NetworkView />}
      </div>

      <FlightModal />
    </div>
  );
};

export default FlightTracker;

import React, { useState, useEffect, useMemo } from 'react';
import Icon from './common/Icon';
import { Link } from 'react-router-dom';
import { AddToInvestigationButton } from './common/AddToInvestigationButton';
import { Select } from './common/Select';

interface Property {
  id: number;
  pcn: string;
  owner_name_1: string | null;
  owner_name_2: string | null;
  street_name: string | null;
  site_address: string | null;
  total_tax_value: number | null;
  acres: number | null;
  property_use: string | null;
  year_built: number | null;
  bedrooms: number | null;
  full_bathrooms: number | null;
  half_bathrooms: number | null;
  stories: number | null;
  building_value: number | null;
  building_area: number | null;
  living_area: number | null;
  is_epstein_property: number;
  is_known_associate: number;
  linked_entity_id: number | null;
}

interface PropertyStats {
  totalProperties: number;
  epsteinProperties: number;
  knownAssociateProperties: number;
  avgTaxValue: number;
  maxTaxValue: number;
  propertyTypes: { type: string; count: number }[];
}

interface ValueDistribution {
  range: string;
  count: number;
  min: number;
  max: number;
}

const PropertyBrowser: React.FC = () => {
  const [properties, setProperties] = useState<Property[]>([]);
  const [stats, setStats] = useState<PropertyStats | null>(null);
  const [valueDistribution, setValueDistribution] = useState<ValueDistribution[]>([]);
  const [topOwners, setTopOwners] = useState<
    { owner_name: string; property_count: number; total_value: number }[]
  >([]);
  const [knownAssociates, setKnownAssociates] = useState<Property[]>([]);
  const [loading, setLoading] = useState(true);
  const [dataUnavailable, setDataUnavailable] = useState(false);
  const [viewMode, setViewMode] = useState<'browse' | 'associates' | 'analytics'>('browse');

  // Filters
  const [searchTerm, setSearchTerm] = useState('');
  const [propertyType, setPropertyType] = useState('');
  const [minValue, setMinValue] = useState('');
  const [maxValue, setMaxValue] = useState('');
  const [showAssociatesOnly, setShowAssociatesOnly] = useState(false);
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);

  const propertyTypes = useMemo(() => {
    return stats?.propertyTypes || [];
  }, [stats]);

  useEffect(() => {
    loadInitialData();
  }, []);

  useEffect(() => {
    loadProperties();
  }, [searchTerm, propertyType, minValue, maxValue, showAssociatesOnly, page]);

  const loadInitialData = async () => {
    try {
      const statsRes = await fetch('/api/properties/stats');

      // Check if we got a valid JSON response (not 404 HTML page)
      const contentType = statsRes.headers.get('content-type');
      if (!statsRes.ok || !contentType?.includes('application/json')) {
        setDataUnavailable(true);
        setLoading(false);
        return;
      }

      const [distRes, ownersRes, associatesRes] = await Promise.all([
        fetch('/api/properties/value-distribution'),
        fetch('/api/properties/top-owners'),
        fetch('/api/properties/known-associates'),
      ]);

      const statsData = await statsRes.json();

      // Check if stats indicate no data
      if (
        !statsData ||
        statsData.totalProperties === 0 ||
        statsData.totalProperties === undefined
      ) {
        setDataUnavailable(true);
        setLoading(false);
        return;
      }

      const [distData, ownersData, associatesData] = await Promise.all([
        distRes.ok ? distRes.json() : [],
        ownersRes.ok ? ownersRes.json() : [],
        associatesRes.ok ? associatesRes.json() : [],
      ]);

      setStats(statsData);
      setValueDistribution(distData || []);
      setTopOwners(ownersData || []);
      setKnownAssociates(associatesData || []);
    } catch (error) {
      console.error('Failed to load property stats:', error);
      setDataUnavailable(true);
    }
  };

  const loadProperties = async () => {
    setLoading(true);
    try {
      const params = new URLSearchParams();
      if (searchTerm) params.append('search', searchTerm);
      if (propertyType) params.append('type', propertyType);
      if (minValue) params.append('minValue', minValue);
      if (maxValue) params.append('maxValue', maxValue);
      if (showAssociatesOnly) params.append('associatesOnly', 'true');
      params.append('page', page.toString());
      params.append('limit', '50');

      const res = await fetch(`/api/properties?${params}`);
      const data = await res.json();

      setProperties(data.properties || []);
      setTotalPages(data.totalPages || 1);
    } catch (error) {
      console.error('Failed to load properties:', error);
    } finally {
      setLoading(false);
    }
  };

  const formatCurrency = (value: number | null | undefined) => {
    if (value === null || value === undefined || isNaN(value)) return '$0';
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
      maximumFractionDigits: 0,
    }).format(value);
  };

  const formatNumber = (value: number | null | undefined) => {
    if (value === null || value === undefined || isNaN(value)) return '0';
    return new Intl.NumberFormat('en-US').format(value);
  };

  // Show coming soon state if data is unavailable
  if (dataUnavailable) {
    return (
      <div className="property-browser">
        <div className="property-header">
          <h1>
            <Icon name="Building" size="lg" />
            Palm Beach Property Records
          </h1>
          <p className="subtitle">Explore properties from Palm Beach County public records</p>
        </div>

        <div className="flex flex-col items-center justify-center py-16 text-center">
          <div className="w-24 h-24 bg-emerald-500/10 rounded-full flex items-center justify-center mb-6">
            <Icon name="Building" size="xl" className="text-emerald-400" />
          </div>
          <h2 className="text-2xl font-bold text-white mb-3">Property Data Coming Soon</h2>
          <p className="text-slate-400 max-w-md mb-6">
            The Palm Beach County property records integration is currently in development. This
            feature will allow you to explore property ownership records and identify connections to
            known associates.
          </p>
          <div className="flex items-center gap-2 text-sm text-emerald-400 bg-emerald-500/10 px-4 py-2 rounded-lg">
            <Icon name="Clock" size="sm" />
            <span>Expected in a future update</span>
          </div>
        </div>
      </div>
    );
  }

  const BrowseView = () => (
    <div className="property-browse">
      {/* Filters Bar */}
      <div className="bg-slate-800/50 p-4 border-b border-slate-700/50 backdrop-blur-md sticky top-0 z-10">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row gap-4">
          <div className="flex-1 relative">
            <Icon
              name="Search"
              className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"
              size="sm"
            />
            <input
              type="text"
              placeholder="Search properties, owners, addresses..."
              value={searchTerm}
              onChange={(e) => {
                setSearchTerm(e.target.value);
                setPage(1);
              }}
              className="w-full bg-slate-900/50 border border-slate-700 rounded-lg pl-10 pr-4 py-2 text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-blue-500/50"
            />
          </div>
          <div className="flex flex-wrap gap-4">
            <Select
              containerClassName="min-w-[180px]"
              value={propertyType}
              onChange={(e) => {
                setPropertyType(e.target.value);
                setPage(1);
              }}
              options={[
                { value: '', label: 'All Property Types' },
                ...propertyTypes.map((t) => ({ value: t.type, label: t.type })),
              ]}
            />

            <Select
              containerClassName="min-w-[160px]"
              value={minValue}
              onChange={(e) => {
                setMinValue(e.target.value);
                setPage(1);
              }}
              options={[
                { value: '', label: 'Min Value: Any' },
                { value: '1000000', label: '$1M+' },
                { value: '5000000', label: '$5M+' },
                { value: '10000000', label: '$10M+' },
                { value: '50000000', label: '$50M+' },
              ]}
            />

            <div className="flex items-center gap-2 bg-slate-900/50 border border-slate-700 rounded-lg px-4">
              <label className="flex items-center gap-2 cursor-pointer text-sm font-medium text-slate-300 select-none">
                <input
                  type="checkbox"
                  checked={showAssociatesOnly}
                  onChange={(e) => {
                    setShowAssociatesOnly(e.target.checked);
                    setPage(1);
                  }}
                  className="w-4 h-4 rounded border-slate-600 text-blue-500 focus:ring-blue-500/50 bg-slate-800"
                />
                Known Associates Only
              </label>
            </div>

            {/* View Toggle */}
            <div className="flex bg-slate-900/50 rounded-lg p-1 border border-slate-700">
              <button
                onClick={() => setViewMode('browse')}
                className={`p-2 rounded-md transition-all ${viewMode === 'browse' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
                title="Browse List"
              >
                <Icon name="List" size="sm" />
              </button>
              <button
                onClick={() => setViewMode('associates')}
                className={`p-2 rounded-md transition-all ${viewMode === 'associates' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
                title="Known Associates"
              >
                <Icon name="Users" size="sm" />
              </button>
              <button
                onClick={() => setViewMode('analytics')}
                className={`p-2 rounded-md transition-all ${viewMode === 'analytics' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
                title="Analytics"
              >
                <Icon name="BarChart3" size="sm" />
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Property List */}
      {loading ? (
        <div className="loading-state">
          <Icon name="Loader2" className="spin" size="sm" /> Loading properties...
        </div>
      ) : (
        <>
          <div className="property-grid">
            {properties.map((property) => (
              <div
                key={property.id}
                className={`property-card ${property.is_known_associate ? 'flagged' : ''}`}
              >
                {property.is_known_associate === 1 && (
                  <div className="associate-badge">
                    <Icon name="AlertTriangle" size="sm" />
                    Known Associate
                  </div>
                )}
                {property.is_epstein_property === 1 && (
                  <div className="associate-badge epstein">
                    <Icon name="AlertTriangle" size="sm" />
                    Epstein Property
                  </div>
                )}
                <div className="property-header">
                  <h4>{property.owner_name_1 || 'Unknown Owner'}</h4>
                  <span className="property-value">{formatCurrency(property.total_tax_value)}</span>
                </div>
                <div className="property-address">
                  <Icon name="MapPin" size="sm" />
                  {property.site_address || property.street_name || 'Address N/A'}
                </div>
                <div className="property-details">
                  <span>
                    <strong>Type:</strong> {property.property_use || 'N/A'}
                  </span>
                  <span>
                    <strong>Built:</strong> {property.year_built || 'N/A'}
                  </span>
                  {property.bedrooms && property.bedrooms > 0 && (
                    <span>
                      <strong>Beds:</strong> {property.bedrooms}
                    </span>
                  )}
                  {property.full_bathrooms && property.full_bathrooms > 0 && (
                    <span>
                      <strong>Baths:</strong> {property.full_bathrooms}
                    </span>
                  )}
                  {property.living_area && property.living_area > 0 && (
                    <span>
                      <strong>Living:</strong> {formatNumber(property.living_area)} sqft
                    </span>
                  )}
                  {property.acres && property.acres > 0 && (
                    <span>
                      <strong>Acres:</strong> {property.acres.toFixed(2)}
                    </span>
                  )}
                </div>
                <div className="property-values">
                  <div>
                    <span className="label">Building</span>
                    <span className="value">{formatCurrency(property.building_value)}</span>
                  </div>
                </div>
                {property.is_known_associate === 1 && property.linked_entity_id && (
                  <Link to={`/entity/${property.linked_entity_id}`} className="associate-link">
                    <Icon name="User" size="sm" />
                    View Entity Profile
                  </Link>
                )}
                <div
                  className="property-actions"
                  style={{
                    marginTop: '12px',
                    paddingTop: '12px',
                    borderTop: '1px solid rgba(255,255,255,0.1)',
                  }}
                >
                  <AddToInvestigationButton
                    item={{
                      id: String(property.id),
                      title: `${property.owner_name_1 || 'Unknown'} - ${property.site_address || property.street_name || 'Unknown Address'}`,
                      description: `${property.property_use || 'Property'} valued at ${formatCurrency(property.total_tax_value)}${property.is_known_associate ? ' (Known Associate)' : ''}`,
                      type: 'property',
                      sourceId: String(property.id),
                      metadata: {
                        owner: property.owner_name_1,
                        address: property.site_address || property.street_name,
                        value: property.total_tax_value,
                        isKnownAssociate: property.is_known_associate === 1,
                        linkedEntityId: property.linked_entity_id,
                      },
                    }}
                    variant="quick"
                    className="w-full justify-center"
                  />
                </div>
              </div>
            ))}
          </div>

          {/* Pagination */}
          <div className="pagination">
            <button
              onClick={() => setPage((p) => Math.max(1, p - 1))}
              disabled={page === 1}
              className="page-btn"
            >
              <Icon name="ChevronLeft" size="sm" />
            </button>
            <span className="page-info">
              Page {page} of {totalPages}
            </span>
            <button
              onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
              disabled={page === totalPages}
              className="page-btn"
            >
              <Icon name="ChevronRight" size="sm" />
            </button>
          </div>
        </>
      )}
    </div>
  );

  const AssociatesView = () => (
    <div className="associates-view">
      <div className="associates-header">
        <h3>
          <Icon name="AlertTriangle" size="md" />
          Properties Linked to Known Associates
        </h3>
        <p className="associates-description">
          {knownAssociates.length} properties have been flagged as potentially linked to known
          associates of Jeffrey Epstein based on name matching with entities in the archive.
        </p>
      </div>

      <div className="associates-grid">
        {knownAssociates.map((property) => (
          <div key={property.id} className="associate-property-card">
            <div className="associate-info">
              <div className="associate-name">
                <Icon name="User" size="sm" />
                {property.owner_name_1 || 'Unknown'}
              </div>
              {property.linked_entity_id && (
                <Link to={`/entity/${property.linked_entity_id}`} className="view-profile-btn">
                  View Profile <Icon name="ExternalLink" size="sm" />
                </Link>
              )}
            </div>
            <div className="property-info">
              <h4>{property.owner_name_1 || 'Unknown Owner'}</h4>
              <p className="address">
                {property.site_address || property.street_name || 'Address N/A'}
              </p>
              <div className="value-row">
                <span className="total-value">{formatCurrency(property.total_tax_value)}</span>
                <span className="property-type">{property.property_use || 'N/A'}</span>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  const AnalyticsView = () => (
    <div className="analytics-view">
      {/* Value Distribution */}
      <div className="analytics-section">
        <h3>Property Value Distribution</h3>
        <div className="value-chart">
          {valueDistribution.map((bucket, i) => {
            const maxCount = Math.max(...valueDistribution.map((v) => v.count));
            const height = (bucket.count / maxCount) * 100;
            return (
              <div key={i} className="chart-bar">
                <div
                  className="bar-fill"
                  style={{ height: `${height}%` }}
                  title={`${bucket.count} properties`}
                />
                <span className="bar-label">{bucket.range}</span>
                <span className="bar-count">{formatNumber(bucket.count)}</span>
              </div>
            );
          })}
        </div>
      </div>

      {/* Top Owners */}
      <div className="analytics-section">
        <h3>Top Property Owners</h3>
        <div className="top-owners-list">
          {topOwners.slice(0, 20).map((owner, i) => (
            <div key={i} className="owner-row">
              <span className="rank">#{i + 1}</span>
              <span className="owner-name">{owner.owner_name}</span>
              <span className="property-count">{owner.property_count} properties</span>
              <span className="total-value">{formatCurrency(owner.total_value)}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Property Types */}
      <div className="analytics-section">
        <h3>Property Types</h3>
        <div className="type-breakdown">
          {propertyTypes.slice(0, 10).map((pt) => (
            <div key={pt.type} className="type-item">
              <span className="type-name">{pt.type || 'Unknown'}</span>
              <div className="type-bar">
                <div
                  className="type-fill"
                  style={{
                    width: `${(pt.count / (stats?.totalProperties || 1)) * 100}%`,
                  }}
                />
              </div>
              <span className="type-count">{formatNumber(pt.count)}</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );

  return (
    <div className="property-browser">
      {/* Header */}
      <div className="browser-header">
        <div className="header-content">
          <h1>
            <Icon name="Home" size="lg" />
            Palm Beach Property Records
          </h1>
          <p className="subtitle">
            Explore {stats ? formatNumber(stats.totalProperties) : '...'} properties from Palm Beach
            County public records
          </p>
        </div>

        {/* Stats Summary */}
        {stats && (
          <div className="stats-summary">
            <div className="stat-card">
              <Icon name="Home" size="md" />
              <div className="stat-value">{formatNumber(stats.totalProperties)}</div>
              <div className="stat-label">Total Properties</div>
            </div>
            <div className="stat-card">
              <Icon name="DollarSign" size="md" />
              <div className="stat-value">{formatCurrency(stats.maxTaxValue)}</div>
              <div className="stat-label">Max Value</div>
            </div>
            <div className="stat-card">
              <Icon name="TrendingUp" size="md" />
              <div className="stat-value">{formatCurrency(stats.avgTaxValue)}</div>
              <div className="stat-label">Average Value</div>
            </div>
            <div className="stat-card flagged">
              <Icon name="AlertTriangle" size="md" />
              <div className="stat-value">{stats.knownAssociateProperties}</div>
              <div className="stat-label">Known Associates</div>
            </div>
          </div>
        )}
      </div>

      {/* View Tabs */}
      <div className="view-tabs">
        <button
          className={`tab ${viewMode === 'browse' ? 'active' : ''}`}
          onClick={() => setViewMode('browse')}
        >
          <Icon name="Grid" size="sm" />
          Browse Properties
        </button>
        <button
          className={`tab ${viewMode === 'associates' ? 'active' : ''}`}
          onClick={() => setViewMode('associates')}
        >
          <Icon name="AlertTriangle" size="sm" />
          Known Associates ({knownAssociates.length})
        </button>
        <button
          className={`tab ${viewMode === 'analytics' ? 'active' : ''}`}
          onClick={() => setViewMode('analytics')}
        >
          <Icon name="BarChart3" size="sm" />
          Analytics
        </button>
      </div>

      {/* Content */}
      <div className="browser-content">
        {viewMode === 'browse' && <BrowseView />}
        {viewMode === 'associates' && <AssociatesView />}
        {viewMode === 'analytics' && <AnalyticsView />}
      </div>

      <style>{`
