interface DocumentContentRendererProps {
  document: Document | any; // Accept any for flexibility with legacy types
  searchTerm?: string;
  showRaw?: boolean;
}

export const DocumentContentRenderer: React.FC<DocumentContentRendererProps> = ({
  document: doc,
  searchTerm,
  showRaw = false,
}) => {
  const [showAnnotations, setShowAnnotations] = useState(false);
  // Optimize entity lookup map
  const [entityMap, setEntityMap] = useState<Map<string, any>>(new Map());
  // TODO: Use entities for related entities sidebar - see UNUSED_VARIABLES_RECOMMENDATIONS.md
  const [_entities, setEntities] = useState<any[]>([]);
  const [entityRegexes, setEntityRegexes] = useState<RegExp[]>([]);
  const [showUnredactedHighlights, setShowUnredactedHighlights] = useState(true);

  // Fetch all entities for linking - optimized
  useEffect(() => {
    let mounted = true;
    const fetchEntities = async () => {
      try {
        const entityData = await apiClient.getAllEntities();
        if (!mounted) return;

        setEntities(entityData);

        // Create lookup map and giant regex for single-pass replacement
        const map = new Map();
        // Sort by length desc to match longest names first
        const sorted = [...entityData].sort((a, b) => b.full_name.length - a.full_name.length);

        const terms: string[] = [];
        sorted.forEach((e) => {
          if (e.full_name && e.full_name.length > 3) {
            // Skip very short names to avoid noise
            map.set(e.full_name.toLowerCase(), e);
            terms.push(e.full_name.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'));
          }
        });

        setEntityMap(map);

        // chunk regex if too large
        const CHUNK_SIZE = 500;
        const chunks: RegExp[] = [];
        for (let i = 0; i < terms.length; i += CHUNK_SIZE) {
          const chunk = terms.slice(i, i + CHUNK_SIZE);
          if (chunk.length > 0) {
            chunks.push(new RegExp(`\\b(${chunk.join('|')})\\b`, 'gi'));
          }
        }
        // Store array of regexes instead of single one
        // We need to update state type: [entityRegexes, setEntityRegexes]
        setEntityRegexes(chunks);
      } catch (error) {
        console.error('Error fetching entities for linking:', error);
      }
    };

    fetchEntities();
    return () => {
      mounted = false;
    };
  }, []);

  // Helper to highlight text
  const highlightText = (text: string, term?: string) => {
    if (!term || !text || typeof text !== 'string') return text;

    try {
      const escapeRegExp = (str: string) => str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
      // Only highlight words > 2 chars
      const terms = term.split(/\s+/).filter((t) => t.length > 2);

      if (terms.length === 0) {
        if (term.trim().length > 0) {
          const regex = new RegExp(`(${escapeRegExp(term)})`, 'gi');
          return text.replace(
            regex,
            '<mark class="bg-yellow-500 text-black px-1 rounded">$1</mark>',
          );
        }
        return text;
      }

      const pattern = `(${terms.map(escapeRegExp).join('|')})`;
      const regex = new RegExp(pattern, 'gi');
      return text.replace(regex, '<mark class="bg-yellow-500 text-black px-1 rounded">$1</mark>');
    } catch (e) {
      console.warn('Error highlighting text:', e);
      return text;
    }
  };

  const renderHighlightedText = (text: string, term?: string) => {
    if (!term) return text;
    return <span dangerouslySetInnerHTML={{ __html: highlightText(text, term) }} />;
  };

  // Optimized Helper function to link entities in text
  // eslint-disable-next-line react-hooks/exhaustive-deps -- entityRegexes/entityMap are stable across renders
  const linkEntitiesInText = (text: string) => {
    if (!text || entityRegexes.length === 0 || entityMap.size === 0) return text;

    let processedText = text;
    // Apply each chunk sequentially
    // Note: This could theoretically double-link if terms overlap in weird ways,
    // but with \b boundary and replaced content being a <span>, it should be mostly safe
    // providing we don't match inside the span tags.
    // To be safer, we should use a placeholder approach, but for now let's try sequential.
    // Actually, matching inside HTML tags is a risk.
    // A better approach for massive entity lists is a customized scanner or finding positions first.
    // Given the constraints, we will process chunks but strict word boundaries help.

    // HOWEVER, simpler fix for "Regular expression too large" is often just
    // breaking it up. The risk of replacing inside tags exists if we just chain replace.
    // A robust way: Tokenize text nodes, but that's expensive in React logic here.

    // Let's stick to the current logic but iterating.
    entityRegexes.forEach((regex) => {
      processedText = processedText.replace(regex, (match) => {
        // Check if we are inside a tag (rudimentary check)
        // This is hard to do cleanly in regex replace callback without context.
        // But since we are replacing plain text logic from the start...

        const entity = entityMap.get(match.toLowerCase());
        if (!entity) return match;

        // To prevent recursive replacement of already linked items (if chunks overlap or we re-scan),
        // we could check if match is wrapped. But here we are processing the string.
        // We'll rely on the fact that terms are likely names.
        return `<span class="entity-link" data-entity-id="${entity.id}" data-entity-name="${entity.full_name}" style="color: #60a5fa; text-decoration: underline; cursor: pointer; border-bottom: 1px dotted #60a5fa; padding: 0 1px;" title="Click to view entity details">${match}</span>`;
      });
    });

    return processedText;
  };

  // Add event listener for entity links
  useEffect(() => {
    const handleClick = (e: MouseEvent) => {
      const target = e.target as HTMLElement;
      // Handle clicks on spans within the dangerous HTML
      const link = target.closest('.entity-link');
      if (link) {
        e.preventDefault();
        e.stopPropagation();

        const entityId = link.getAttribute('data-entity-id');
        const entityName = link.getAttribute('data-entity-name');

        if (entityId && entityName) {
          const event = new CustomEvent('entityClick', {
            detail: { id: entityId, name: entityName },
          });
          window.dispatchEvent(event);
        }
      }
    };

    const container = document.body; // or specific container if ref available
    container.addEventListener('click', handleClick);
    return () => container.removeEventListener('click', handleClick);
  }, []);

  // Memoize processed content to avoid re-computation on every render
  const processedContent = useMemo(() => {
    // Use contentRefined if available and not showing raw, otherwise use content
    const rawText = doc.contentRefined && !showRaw ? doc.contentRefined : doc.content;
    // Apply prettifyOCRText unless showRaw is true
    const baseContent = showRaw ? rawText : prettifyOCRText(rawText);

    // Step 1: Apply unredaction token highlighting (baseline diff)
    let content = baseContent as string;
    try {
      const baselineVocab: string | null | undefined = doc.unredaction_metrics?.baselineVocab;
      if (
        showUnredactedHighlights &&
        baselineVocab &&
        typeof content === 'string' &&
        content.length > 0
      ) {
        const baselineTokens = new Set<string>();
        for (const t of baselineVocab.split(/\s+/)) {
          const token = t.trim().toLowerCase();
          if (!token) continue;
          baselineTokens.add(token);
        }

        // Tokenize content and wrap tokens not present in baseline
        const parts: string[] = [];
        const tokenRegex = /([A-Za-z0-9']+|[^A-Za-z0-9']+)/g;
        let match: RegExpExecArray | null;
        while ((match = tokenRegex.exec(content)) !== null) {
          const fragment = match[0];
          if (/^[A-Za-z0-9']+$/.test(fragment)) {
            const key = fragment.toLowerCase();
            if (!baselineTokens.has(key)) {
              // Newly-unredacted token; wrap in subtle highlight
              const escaped = fragment
                .replace(/&/g, '&amp;')
                .replace(/</g, '&lt;')
                .replace(/>/g, '&gt;');
              parts.push(
                `<mark class="bg-emerald-800/40 border border-emerald-500/40 rounded px-0.5 py-0 text-emerald-100" title="Newly unredacted text">${escaped}</mark>`,
              );
            } else {
              parts.push(fragment);
            }
          } else {
            parts.push(fragment);
          }
        }
        content = parts.join('');
      }
    } catch (e) {
      console.warn('Error applying unredaction baseline highlighting:', e);
    }

    // Step 2: Apply entity linking (now optimized single-pass)
    // Only run linking if we have the regex ready
    const contentWithEntities = entityRegexes.length > 0 ? linkEntitiesInText(content) : content;

    // Step 3: Apply search term highlighting on top
    return searchTerm ? highlightText(contentWithEntities, searchTerm) : contentWithEntities;
  }, [
    doc.content,
    showRaw,
    searchTerm,
    doc.unredaction_metrics,
    showUnredactedHighlights,
    linkEntitiesInText,
    entityRegexes,
  ]);

  return (
    <div className="prose prose-invert max-w-none">
      <div className="mb-1 flex items-center justify-between">
        <div className="text-sm text-gray-400 flex items-center gap-2">
          <span>
            {doc.evidenceType === 'email'
              ? '📧 Email Message'
              : doc.evidenceType === 'legal'
                ? '⚖️ Legal Document'
                : doc.evidenceType === 'deposition'
                  ? '📜 Deposition'
                  : doc.evidenceType === 'financial'
                    ? '💰 Financial Record'
                    : doc.fileType?.match(/jpe?g|png|gif|bmp|webp/i)
                      ? '📷 Image'
                      : doc.fileType?.match(/csv|xls/i)
                        ? '📊 Spreadsheet'
                        : 'Select text to add annotations and evidence'}
          </span>
          {doc.contentRefined && !showRaw && (
            <span className="px-2 py-0.5 rounded text-[10px] uppercase font-bold tracking-wider bg-purple-900/40 text-purple-300 border border-purple-500/40">
              🤖 AI Refined
            </span>
          )}
        </div>
        {!doc.fileType?.match(/jpe?g|png|gif|bmp|webp|csv|xls/i) && (
          <div className="flex items-center gap-3">
            {typeof doc.unredaction_metrics?.unredactedTextGain === 'number' && (
              <div className="text-xs text-emerald-400 flex items-center gap-2">
                <span className="inline-flex items-center px-2 py-0.5 rounded-full bg-emerald-900/40 border border-emerald-500/40">
                  Unredacted gain:{' '}
                  {Math.round((doc.unredaction_metrics.unredactedTextGain || 0) * 100)}%
                </span>
                <label className="inline-flex items-center gap-1 text-emerald-200/80 cursor-pointer select-none">
                  <input
                    type="checkbox"
                    className="h-3 w-3 rounded border-emerald-500/60 bg-slate-900/60 text-emerald-400 focus:ring-emerald-500/60"
                    checked={showUnredactedHighlights}
                    onChange={(e) => setShowUnredactedHighlights(e.target.checked)}
                  />
                  <span className="text-[11px]">Highlight newly unredacted text</span>
                </label>
              </div>
            )}
            <button
              onClick={() => setShowAnnotations(!showAnnotations)}
              className={`px-3 py-1 text-xs rounded transition-colors ${
                showAnnotations
                  ? 'bg-blue-600 text-white'
                  : 'bg-gray-700 text-gray-300 hover:bg-gray-600'
              }`}
            >
              {showAnnotations ? 'Hide Annotations' : 'Show Annotations'}
            </button>
          </div>
        )}
      </div>

      {/* Legend for unredacted highlighting */}
      {doc.unredaction_metrics?.baselineVocab && (
        <div className="mb-3 text-[11px] text-emerald-200/80 flex items-center gap-2">
          <span className="inline-flex items-center px-1.5 py-0.5 rounded bg-emerald-900/60 border border-emerald-500/50 text-emerald-100">
            Newly unredacted
          </span>
          <span className="text-emerald-100/70">
            Words highlighted in emerald were recovered during automated unredaction compared with
            the original OCR text.
          </span>
        </div>
      )}

      {/* Email Headers Display */}
      {doc.evidenceType === 'email' &&
        (() => {
          // Try to get email headers from metadata, or parse from content
          let emailHeaders = doc.metadata?.emailHeaders;
          let emailBody = doc.content || '';

          // If no emailHeaders in metadata, try to parse from content
          if (!emailHeaders || (!emailHeaders.from && !emailHeaders.to && !emailHeaders.subject)) {
            const content = doc.content || '';
            const lines = content.split('\n').slice(0, 40);
            const headerText = lines.join('\n');

            // Parse common email header patterns
            const fromMatch = headerText.match(/^(?:from|sender):\s*(.+)$/im);
            const toMatch = headerText.match(/^to:\s*(.+)$/im);
            const ccMatch = headerText.match(/^cc:\s*(.+)$/im);
            const subjectMatch = headerText.match(/^(?:subject|re):\s*(.+)$/im);
            const dateMatch = headerText.match(/^(?:date|sent):\s*(.+)$/im);

            if (fromMatch || toMatch || subjectMatch) {
              emailHeaders = {
                from: fromMatch?.[1]?.trim(),
                to: toMatch?.[1]?.trim(),
                cc: ccMatch?.[1]?.trim(),
                subject: subjectMatch?.[1]?.trim(),
                sentDate: dateMatch?.[1]?.trim(),
              };

              // Extract email body (everything after headers)
              // Find the first blank line after headers or after the date line
              let bodyStartIndex = 0;
              const contentLines = content.split('\n');
              for (let i = 0; i < Math.min(contentLines.length, 50); i++) {
                const line = contentLines[i].trim().toLowerCase();
                if (line === '' && i > 3) {
                  bodyStartIndex = i + 1;
                  break;
                }
                // Also stop at common body start patterns
                if (
                  i > 5 &&
                  !line.match(
                    /^(from|to|cc|bcc|subject|date|sent|message-id|reply-to|content-type):/i,
                  )
                ) {
                  bodyStartIndex = i;
                  break;
                }
              }
              if (bodyStartIndex > 0) {
                emailBody = contentLines.slice(bodyStartIndex).join('\n').trim();
              }
            }
          }

          // If we have email headers, show the email client UI
          if (emailHeaders && (emailHeaders.from || emailHeaders.to || emailHeaders.subject)) {
            return (
              <>
                {/* Mock Email Client Header */}
                <div className="bg-slate-800 rounded-lg border border-slate-600 mb-4 overflow-hidden">
                  {/* Email toolbar */}
                  <div className="flex items-center gap-2 px-4 py-2 bg-slate-700 border-b border-slate-600">
                    <span className="text-cyan-400">📧</span>
                    <span className="text-sm text-slate-300 font-medium">Email Message</span>
                  </div>

                  {/* Headers */}
                  <div className="p-4 space-y-2">
                    {emailHeaders.subject && (
                      <div className="text-lg font-semibold text-white mb-3">
                        {emailHeaders.subject}
                      </div>
                    )}

                    {emailHeaders.from && (
                      <div className="flex items-start gap-2">
                        <span className="text-slate-500 text-sm w-14 shrink-0">From:</span>
                        <span className="text-white text-sm">{emailHeaders.from}</span>
                      </div>
                    )}
                    {emailHeaders.to && (
                      <div className="flex items-start gap-2">
                        <span className="text-slate-500 text-sm w-14 shrink-0">To:</span>
                        <span className="text-slate-300 text-sm">{emailHeaders.to}</span>
                      </div>
                    )}
                    {emailHeaders.cc && (
                      <div className="flex items-start gap-2">
                        <span className="text-slate-500 text-sm w-14 shrink-0">Cc:</span>
                        <span className="text-slate-400 text-sm">{emailHeaders.cc}</span>
                      </div>
                    )}
                    {emailHeaders.sentDate && (
                      <div className="flex items-start gap-2">
                        <span className="text-slate-500 text-sm w-14 shrink-0">Date:</span>
                        <span className="text-slate-400 text-sm">{emailHeaders.sentDate}</span>
                      </div>
                    )}
                  </div>
                </div>

                {/* Email Body - show separated from headers */}
                {emailBody && emailBody !== doc.content && (
                  <div className="bg-slate-800/50 rounded-lg p-4 border border-slate-700">
                    <pre className="whitespace-pre-wrap text-sm text-slate-300 font-sans leading-relaxed break-words">
                      {showRaw ? emailBody : prettifyOCRText(emailBody)}
                    </pre>
                  </div>
                )}
              </>
            );
          }

          return null;
        })()}

      {/* Legal Document Viewer */}
      {doc.evidenceType === 'legal' &&
        (() => {
          const content = doc.content || '';

          // Parse legal document patterns
          const caseNumberMatch = content.match(/Case\s*No\.?\s*:?\s*([\w\d\-:]+)/i);
          const courtMatch = content.match(
            /(?:IN THE|UNITED STATES)\s+(?:CIRCUIT COURT|DISTRICT COURT|COURT)[^\n]*/i,
          );
          const plaintiffMatch = content.match(
            /([A-Z][A-Z\s\.\,]+)\s*,?\s*(?:Plaintiff|Petitioner)/i,
          );
          const defendantMatch = content.match(
            /(?:v\.?s?\.?|versus)\s*\n?\s*([A-Z][A-Z\s\.\,]+)\s*,?\s*(?:Defendant|Respondent)?/i,
          );
          const filingDateMatch = content.match(/(?:E-Filed|Filed)\s*(\d{1,2}\/\d{1,2}\/\d{2,4})/i);
          const documentTypeMatch = content.match(
            /(MOTION|ORDER|COMPLAINT|REPLY|RESPONSE|MEMORANDUM|DECLARATION|SUBPOENA|SUMMONS)[^\n]*/i,
          );

          const hasParsedData = caseNumberMatch || courtMatch || plaintiffMatch || defendantMatch;

          if (hasParsedData) {
            return (
              <>
                {/* Legal Document Header */}
                <div className="bg-slate-800 rounded-lg border border-amber-700/50 mb-4 overflow-hidden">
                  {/* Court banner */}
                  <div className="bg-gradient-to-r from-amber-900/50 to-slate-800 px-4 py-3 border-b border-amber-700/30">
                    <div className="flex items-start gap-3">
                      <span className="text-2xl shrink-0">⚖️</span>
                      <div className="min-w-0 flex-1">
                        <div className="text-amber-200 font-semibold text-sm break-words">
                          {courtMatch?.[0]?.trim() || 'Legal Document'}
                        </div>
                        {caseNumberMatch && (
                          <div className="text-amber-400/70 text-xs font-mono mt-1">
                            Case {caseNumberMatch[1]}
                          </div>
                        )}
                      </div>
                    </div>
                  </div>

                  {/* Parties */}
                  {(plaintiffMatch || defendantMatch) && (
                    <div className="p-4 border-t border-slate-700">
                      <div className="flex flex-col md:flex-row gap-4 items-stretch">
                        {plaintiffMatch && (
                          <div className="flex-1 bg-slate-900/50 p-4 rounded border border-slate-700">
                            <div className="text-xs text-amber-400 uppercase mb-2 font-semibold">
                              Plaintiff
                            </div>
                            <div className="text-white font-medium">{plaintiffMatch[1].trim()}</div>
                          </div>
                        )}
                        <div className="flex items-center justify-center px-4">
                          <span className="text-slate-500 text-xl font-light">vs.</span>
                        </div>
                        {defendantMatch && (
                          <div className="flex-1 bg-slate-900/50 p-4 rounded border border-slate-700">
                            <div className="text-xs text-amber-400 uppercase mb-2 font-semibold">
                              Defendant
                            </div>
                            <div className="text-white font-medium">{defendantMatch[1].trim()}</div>
                          </div>
                        )}
                      </div>
                    </div>
                  )}

                  {/* Document type and date */}
                  <div className="px-4 pb-3 flex flex-wrap gap-2">
                    {documentTypeMatch && (
                      <span className="px-2 py-1 bg-amber-900/30 text-amber-200 text-xs rounded">
                        {documentTypeMatch[1]}
                      </span>
                    )}
                    {filingDateMatch && (
                      <span className="px-2 py-1 bg-slate-700 text-slate-300 text-xs rounded">
                        Filed: {filingDateMatch[1]}
                      </span>
                    )}
                  </div>
                </div>

                {/* Document Body */}
                <div className="bg-slate-800/30 rounded-lg p-4 border border-slate-700">
                  <pre className="whitespace-pre-wrap text-sm text-slate-300 font-serif leading-relaxed break-words">
                    {showRaw ? content : prettifyOCRText(content)}
                  </pre>
                </div>
              </>
            );
          }
          return null;
        })()}

      {/* Deposition Viewer */}
      {doc.evidenceType === 'deposition' &&
        (() => {
          const content = doc.content || '';

          // Parse deposition patterns
          const caseMatch = content.match(/Case\s*(?:No\.?)?\s*:?\s*([\w\d\-:]+)/i);
          const witnessMatch = content.match(
            /(?:DEPOSITION OF|EXAMINATION OF|TESTIMONY OF)\s+([A-Z][A-Za-z\s\.]+)/i,
          );
          const dateMatch = content.match(
            /(?:taken on|dated?)\s*:?\s*([A-Za-z]+\s+\d{1,2},?\s+\d{4}|\d{1,2}\/\d{1,2}\/\d{2,4})/i,
          );

          // Parse Q&A content
          const lines = content.split('\n');
          const qaContent: { type: 'q' | 'a' | 'text'; content: string }[] = [];
          let currentBlock = { type: 'text' as 'q' | 'a' | 'text', content: '' };

          for (const line of lines) {
            const isQuestion = /^\s*Q[:\.]?\s/i.test(line);
            const isAnswer = /^\s*A[:\.]?\s/i.test(line);

            if (isQuestion) {
              if (currentBlock.content) qaContent.push({ ...currentBlock });
              currentBlock = { type: 'q', content: line.replace(/^\s*Q[:\.]?\s*/i, '') };
            } else if (isAnswer) {
              if (currentBlock.content) qaContent.push({ ...currentBlock });
              currentBlock = { type: 'a', content: line.replace(/^\s*A[:\.]?\s*/i, '') };
            } else {
              currentBlock.content += '\n' + line;
            }
          }
          if (currentBlock.content) qaContent.push(currentBlock);

          const hasQA = qaContent.some((b) => b.type === 'q' || b.type === 'a');

          return (
            <>
              {/* Deposition Header */}
              <div className="bg-slate-800 rounded-lg border border-purple-700/50 mb-4 overflow-hidden">
                <div className="bg-gradient-to-r from-purple-900/50 to-slate-800 px-4 py-3 border-b border-purple-700/30">
                  <div className="flex items-center gap-2">
                    <span className="text-2xl">📜</span>
                    <div>
                      <div className="text-purple-200 font-semibold text-sm">
                        {witnessMatch
                          ? `Deposition of ${witnessMatch[1].trim()}`
                          : 'Deposition Transcript'}
                      </div>
                      {caseMatch && (
                        <div className="text-purple-400/70 text-xs font-mono">
                          Case {caseMatch[1]}
                        </div>
                      )}
                    </div>
                  </div>
                </div>

                {dateMatch && (
                  <div className="px-4 py-2 text-xs text-slate-400">📅 {dateMatch[1]}</div>
                )}
              </div>

              {/* Q&A Content */}
              {hasQA ? (
                <div className="space-y-3">
                  {qaContent.map((block, idx) => (
                    <div
                      key={idx}
                      className={`rounded-lg p-3 ${
                        block.type === 'q'
                          ? 'bg-blue-900/20 border-l-4 border-blue-500'
                          : block.type === 'a'
                            ? 'bg-green-900/20 border-l-4 border-green-500 ml-4'
                            : 'bg-slate-800/50'
                      }`}
                    >
                      {block.type !== 'text' && (
                        <div
                          className={`text-xs font-semibold mb-1 ${
                            block.type === 'q' ? 'text-blue-400' : 'text-green-400'
                          }`}
                        >
                          {block.type === 'q' ? 'QUESTION' : 'ANSWER'}
                        </div>
                      )}
                      <div className="text-sm text-slate-300 whitespace-pre-wrap break-words">
                        {block.content.trim()}
                      </div>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="bg-slate-800/30 rounded-lg p-4 border border-slate-700">
                  <pre className="whitespace-pre-wrap text-sm text-slate-300 font-mono leading-relaxed break-words">
                    {showRaw ? content : prettifyOCRText(content)}
                  </pre>
                </div>
              )}
            </>
          );
        })()}

      {/* Article Viewer */}
      {doc.evidenceType === 'article' &&
        (() => {
          const content = doc.content || '';
          const lines = content.split('\n').filter((l: string) => l.trim());

          // Try to extract article metadata
          const dateMatch = content.match(
            /(\d{1,2}\/\d{1,2}\/\d{2,4})|([A-Z][a-z]+\s+\d{1,2},?\s+\d{4})/,
          );
          const bylineMatch = content.match(/(?:By|BY)\s+([A-Za-z\s\.]+?)(?:\n|$)/);
          const sourceMatch = content.match(
            /(U\.?S\.?\s*News|New York|Daily News|Times|Post|Journal|Magazine|AVENUE|Tribune)/i,
          );

          // First substantial line is likely headline
          const headline = lines.find(
            (l: string) => l.length > 20 && l.length < 200 && !/^\d|^http|^www/i.test(l),
          );
          const headlineIdx = headline ? lines.indexOf(headline) : -1;

          // Body starts after headline
          const bodyLines = headlineIdx >= 0 ? lines.slice(headlineIdx + 1) : lines;
          const body = bodyLines.join('\n\n');

          return (
            <>
              {/* Article Header */}
              <div className="bg-slate-800 rounded-lg border border-cyan-700/50 mb-4 overflow-hidden">
                {/* Source bar */}
                <div className="bg-gradient-to-r from-cyan-900/50 to-slate-800 px-4 py-2 border-b border-cyan-700/30 flex items-center gap-3">
                  <span className="text-xl">📰</span>
                  {sourceMatch && (
                    <span className="text-cyan-300 font-medium text-sm">{sourceMatch[1]}</span>
                  )}
                  {dateMatch && <span className="text-slate-400 text-xs">• {dateMatch[0]}</span>}
                </div>

                {/* Headline */}
                {headline && (
                  <div className="p-4">
                    <h2 className="text-xl md:text-2xl font-bold text-white leading-tight mb-2">
                      {headline}
                    </h2>
                    {bylineMatch && (
                      <div className="text-cyan-400 text-sm">By {bylineMatch[1].trim()}</div>
                    )}
                  </div>
                )}
              </div>

              {/* Article Body */}
              <div className="bg-slate-800/30 rounded-lg p-6 border border-slate-700">
                <div className="prose prose-invert prose-lg max-w-none break-words">
                  {body.split('\n\n').map((para: string, idx: number) => (
                    <p
                      key={idx}
                      className="text-slate-300 leading-relaxed mb-4 first-letter:text-2xl first-letter:font-bold first-letter:text-cyan-400"
                    >
                      {para.trim()}
                    </p>
                  ))}
                </div>
              </div>
            </>
          );
        })()}

      {/* Image Viewer for image files */}
      {doc.fileType?.match(/jpe?g|png|gif|bmp|webp/i) ? (
        <div className="flex flex-col items-center">
          <img
            src={`/api/documents/${doc.id}/file`}
            alt={doc.title}
            className="max-w-full max-h-[70vh] object-contain rounded-lg shadow-lg"
            onError={(e) => {
              // Fallback to showing OCR text if image fails to load
              (e.target as HTMLImageElement).style.display = 'none';
              const parent = (e.target as HTMLImageElement).parentElement;
              if (parent) {
                parent.innerHTML = `<pre class="whitespace-pre-wrap text-sm text-gray-300 font-mono leading-relaxed break-words">${doc.content || 'No content available'}</pre>`;
              }
            }}
          />
          {doc.content && doc.content.trim() && (
            <div className="mt-4 w-full">
              <details className="bg-gray-800 rounded-lg p-4 border border-gray-700">
                <summary className="cursor-pointer text-sm text-gray-400 hover:text-white">
                  📝 OCR Extracted Text ({doc.content.split(/\s+/).length} words)
                </summary>
                <pre className="mt-4 whitespace-pre-wrap text-xs text-gray-400 font-mono leading-relaxed max-h-48 overflow-y-auto break-words">
                  {showRaw ? doc.content : prettifyOCRText(doc.content)}
                </pre>
              </details>
            </div>
          )}
        </div>
      ) : doc.fileType?.match(/csv|xls/i) || doc.evidenceType === 'financial' ? (
        /* CSV/Financial Table Viewer */
        <div className="overflow-x-auto">
          <div className="bg-gray-800 rounded-lg p-4 border border-gray-700 mb-4">
            <div className="flex items-center gap-2 text-sm text-gray-400">
              <span>💰</span>
              <span>Financial Data / Spreadsheet</span>
            </div>
          </div>
          {(() => {
            const lines = (doc.content || '').split('\n').filter((l: string) => l.trim());
            if (lines.length === 0) return <p className="text-gray-400">No data available</p>;

            // Try to parse as CSV
            const rows = lines.map((line: string) => line.split(/[,\t]/));
            const hasHeader = rows.length > 1;

            return (
              <table className="w-full text-sm text-left border-collapse">
                {hasHeader && (
                  <thead className="bg-gray-800 text-gray-300 uppercase text-xs">
                    <tr>
                      {rows[0].map((cell: string, i: number) => (
                        <th key={i} className="px-4 py-3 border border-gray-700 whitespace-nowrap">
                          {cell.trim()}
                        </th>
                      ))}
                    </tr>
                  </thead>
                )}
                <tbody>
                  {rows.slice(hasHeader ? 1 : 0).map((row: string[], rowIdx: number) => (
                    <tr key={rowIdx} className={rowIdx % 2 === 0 ? 'bg-gray-900' : 'bg-gray-800'}>
                      {row.map((cell, cellIdx) => (
                        <td
                          key={cellIdx}
                          className="px-4 py-2 border border-gray-700 text-gray-300 whitespace-nowrap"
                        >
                          {cell.trim()}
                        </td>
                      ))}
                    </tr>
                  ))}
                </tbody>
              </table>
            );
          })()}
        </div>
      ) : showAnnotations ? (
        <DocumentAnnotationSystem
          documentId={doc.id}
          content={doc.content}
          searchTerm={searchTerm}
          renderHighlightedText={renderHighlightedText}
        />
      ) : (
        <div className={`grid gap-6 ${doc.originalFileUrl ? 'lg:grid-cols-2' : 'grid-cols-1'}`}>
          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <h3 className="text-sm font-medium text-gray-400">Extracted Text</h3>
              {doc.page_number && (
                <span className="text-xs bg-gray-700 px-2 py-0.5 rounded text-gray-300">
                  Page {doc.page_number}
                </span>
              )}
            </div>
            <pre
              className="whitespace-pre-wrap text-sm text-gray-300 font-mono leading-relaxed break-words bg-gray-900/50 p-4 rounded-lg border border-gray-700/50 min-h-[600px] overflow-y-auto max-h-[80vh]"
              dangerouslySetInnerHTML={{
                __html: processedContent,
              }}
            />
          </div>

          {doc.originalFileUrl && (
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <h3 className="text-sm font-medium text-gray-400">Original Document</h3>
                <a
                  href={doc.originalFileUrl}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-xs text-blue-400 hover:text-blue-300 flex items-center gap-1"
                >
                  Open in New Tab ↗
                </a>
              </div>
              <div className="bg-white rounded-lg border border-gray-700 overflow-hidden h-full min-h-[600px] max-h-[80vh]">
                <iframe
                  src={`${doc.originalFileUrl}${doc.page_number ? `#page=${doc.page_number}` : ''}`}
                  className="w-full h-full border-none"
                  title="Original Document Content"
                />
              </div>
            </div>
          )}
        </div>
      )}

      {/* Related Entities Section (Surfaced Feature) */}
      {_entities.length > 0 && (
        <div className="mt-8 pt-6 border-t border-slate-700">
          <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-widest mb-4">
            Mentions & Related Entities
          </h3>
          <div className="flex flex-wrap gap-2">
            {(() => {
              // Optimization: Only regex match if we have entities
              if (!_entities.length || entityRegexes.length === 0)
                return <span className="text-gray-500 text-xs">No entities detected yet.</span>;

              // Find unique entities present in content
              // We use the same regex used for highlighting/linking
              const text = doc.content || '';
              const matches = new Set<string>();

              // Iterate over all chunks
              for (const regex of entityRegexes) {
                let match;
                regex.lastIndex = 0;
                // We limit to first 50 unique matches to avoid perf kill on huge docs
                while ((match = regex.exec(text)) !== null) {
                  matches.add(match[0].toLowerCase());
                  if (matches.size > 50) break;
                }
                if (matches.size > 50) break;
              }

              const found = _entities.filter((e) => matches.has(e.full_name.toLowerCase()));

              if (found.length === 0)
                return (
                  <span className="text-gray-500 text-xs">No entities detected in this text.</span>
                );

              return found.map((e) => (
                <span
                  key={e.id}
                  className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-900/30 text-blue-200 border border-blue-500/30 cursor-pointer hover:bg-blue-800 transition-colors"
                  onClick={(evt) => {
                    evt.preventDefault();
                    const event = new CustomEvent('entityClick', {
                      detail: { id: e.id, name: e.full_name },
                    });
                    window.dispatchEvent(event);
                  }}
                >
                  {e.full_name}
                  {e.entity_type && (
                    <span className="ml-1.5 opacity-50 text-[10px] uppercase">{e.entity_type}</span>
                  )}
                </span>
              ));
            })()}
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef, useCallback } from 'react';
import {
  Mail,
  Inbox,
  Search,
  ChevronDown,
  ChevronRight,
  ChevronLeft,
  Clock,
  User,
  Loader2,
  Archive,
  Reply,
  Forward,
  Trash2,
  Users,
  Bell,
  Tag,
  Star,
  Link2,
  ExternalLink,
  Book, // Added Book icon for Black Book
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Link, useNavigate, useSearchParams } from 'react-router-dom';
import { apiClient } from '../../services/apiClient';
import { Document } from '../../types/documents';
import { AddToInvestigationButton } from '../common/AddToInvestigationButton';
import { EvidenceModal } from '../common/EvidenceModal';

// --- Types ---

interface Email extends Document {
  sender?: string;
  recipient?: string;
  subject?: string;
  threadId?: string;
  isRead?: boolean;
  date: string;
  summary?: string;
  category?: 'primary' | 'updates' | 'promotions' | 'social';
  isFromKnownEntity?: boolean;
  knownEntityName?: string;
}

type EmailCategory = 'all' | 'primary' | 'updates' | 'promotions';

interface Thread {
  id: string;
  subject: string;
  lastMessageDate: string;
  messages: Email[];
  participantNames: string[];
  snippet: string;
  hasAttachments: boolean;
  unreadCount: number;
}

interface Mailbox {
  id: string;
  label: string;
  icon: React.ElementType;
  count?: number;
}

type SortField = 'date' | 'sender' | 'subject';
type SortOrder = 'asc' | 'desc';

const PAGE_SIZE = 500;

// --- iOS Mail-Style Email Client ---

export const EmailClient: React.FC = () => {
  const [loading, setLoading] = useState(true);
  const [loadingMore, setLoadingMore] = useState(false);
  const [threads, setThreads] = useState<Thread[]>([]);
  const [selectedThreadId, setSelectedThreadId] = useState<string | null>(null);
  const [selectedAccount, setSelectedAccount] = useState<string>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [debouncedSearchTerm, setDebouncedSearchTerm] = useState('');
  const [sortField, setSortField] = useState<SortField>('date');
  const [sortOrder, setSortOrder] = useState<SortOrder>('desc');
  const [showMailboxDrawer, setShowMailboxDrawer] = useState(false);

  const [currentPage, setCurrentPage] = useState(1);
  const [totalEmails, setTotalEmails] = useState(0);
  const [loadedEmails, setLoadedEmails] = useState(0);
  const [hasMore, setHasMore] = useState(true);
  const [allDocs, setAllDocs] = useState<any[]>([]);
  const [activeCategory, setActiveCategory] = useState<EmailCategory>('primary'); // Default to primary (real people)
  const [categoryCounts, setCategoryCounts] = useState<Record<string, number>>({});

  const listRef = useRef<HTMLDivElement>(null);
  const isMobileDetail = !!selectedThreadId;

  // Entity Support
  const [selectedEntity, setSelectedEntity] = useState<any | null>(null);
  const [loadingEntityId, setLoadingEntityId] = useState<number | null>(null);

  const handleEntityClick = async (entityId: number, entityName: string) => {
    try {
      setLoadingEntityId(entityId);
      const entity = await apiClient.getEntity(String(entityId));
      setSelectedEntity(entity);
    } catch (error) {
      console.error('Error fetching entity:', error);
    } finally {
      setLoadingEntityId(null);
    }
  };

  // Mailbox definitions
  const mailboxes: Mailbox[] = useMemo(
    () => [
      { id: 'all', label: 'All Inboxes', icon: Inbox, count: totalEmails },
      { id: 'barak', label: 'Ehud Barak', icon: Mail },
      { id: 'jee', label: 'Jeffrey Epstein', icon: Mail },
      { id: 'gmax', label: 'Ghislaine Maxwell', icon: Mail },
      { id: 'oversight', label: 'House Oversight', icon: Mail },
    ],
    [totalEmails],
  );

  const currentMailbox = mailboxes.find((m) => m.id === selectedAccount) || mailboxes[0];

  // Debounce search term for performance
  useEffect(() => {
    const timer = setTimeout(() => setDebouncedSearchTerm(searchTerm), 300);
    return () => clearTimeout(timer);
  }, [searchTerm]);

  const [searchParams] = useSearchParams();

  useEffect(() => {
    const q = searchParams.get('search');
    if (q) setSearchTerm(q);
  }, [searchParams]);

  useEffect(() => {
    loadInitialEmails();
    loadCategoryCounts();
    // eslint-disable-next-line react-hooks/exhaustive-deps -- loadInitialEmails is stable and only runs on mount
  }, []);

  // Reload when category changes
  useEffect(() => {
    loadInitialEmails();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [activeCategory]);

  const loadCategoryCounts = async () => {
    try {
      const res = await fetch('/api/emails/categories');
      if (res.ok) {
        const counts = await res.json();
        setCategoryCounts(counts);
      }
    } catch (e) {
      console.error('Failed to load category counts', e);
    }
  };

  const loadInitialEmails = async () => {
    setLoading(true);
    try {
      // Use the new category-filtered endpoint
      const categoryParam = activeCategory !== 'all' ? `&category=${activeCategory}` : '';
      const res = await fetch(`/api/emails?page=1&limit=${PAGE_SIZE}${categoryParam}`);
      if (!res.ok) throw new Error('Failed to fetch');
      const response = await res.json();
      setAllDocs(response.data);
      setTotalEmails(response.total);
      setLoadedEmails(response.data.length);
      setHasMore(response.data.length < response.total);
      setCurrentPage(1);
      processDocsToThreads(response.data);
    } catch (e) {
      console.error('Failed to load emails', e);
    } finally {
      setLoading(false);
    }
  };

  const loadMoreEmails = useCallback(async () => {
    if (loadingMore || !hasMore) return;
    setLoadingMore(true);
    try {
      const nextPage = currentPage + 1;
      const categoryParam = activeCategory !== 'all' ? `&category=${activeCategory}` : '';
      const res = await fetch(`/api/emails?page=${nextPage}&limit=${PAGE_SIZE}${categoryParam}`);
      if (!res.ok) throw new Error('Failed to fetch');
      const response = await res.json();
      if (response.data.length === 0) {
        setHasMore(false);
        return;
      }
      const newDocs = [...allDocs, ...response.data];
      setAllDocs(newDocs);
      setLoadedEmails(newDocs.length);
      setCurrentPage(nextPage);
      setHasMore(newDocs.length < response.total);
      processDocsToThreads(newDocs);
    } catch (e) {
      console.error('Failed to load more emails', e);
    } finally {
      setLoadingMore(false);
    }
  }, [loadingMore, hasMore, currentPage, allDocs, activeCategory]);

  const processDocsToThreads = (docs: any[]) => {
    const threadsMap = new Map<string, Thread>();

    for (const doc of docs) {
      const threadId = doc.metadata?.thread_id || doc.id;
      const sender = doc.metadata?.from || doc.metadata?.sender || 'Unknown Sender';
      const recipient = doc.metadata?.to || doc.metadata?.recipient || '';
      const subject = doc.metadata?.subject || doc.title || 'No Subject';
      const snippet = cleanSnippet(doc.content || doc.summary || '');

      const email: Email = {
        ...doc,
        sender,
        recipient,
        subject,
        threadId,
        date: doc.date || doc.created_at || new Date().toISOString(),
        isRead: true,
      };

      if (threadsMap.has(threadId)) {
        const thread = threadsMap.get(threadId)!;
        thread.messages.push(email);
        if (new Date(email.date) > new Date(thread.lastMessageDate)) {
          thread.lastMessageDate = email.date;
          thread.snippet = snippet;
        }
        if (!thread.participantNames.includes(sender)) {
          thread.participantNames.push(sender);
        }
      } else {
        threadsMap.set(threadId, {
          id: threadId,
          subject,
          lastMessageDate: email.date,
          messages: [email],
          participantNames: [sender],
          snippet,
          hasAttachments: false,
          unreadCount: 0,
        });
      }
    }

    setThreads(Array.from(threadsMap.values()));
  };

  function cleanSnippet(text: string): string {
    return text
      .replace(/From:.*?\n/gi, '')
      .replace(/To:.*?\n/gi, '')
      .replace(/Subject:.*?\n/gi, '')
      .replace(/Date:.*?\n/gi, '')
      .replace(/\n+/g, ' ')
      .trim()
      .slice(0, 150);
  }

  const handleScroll = useCallback(
    (e: React.UIEvent<HTMLDivElement>) => {
      const target = e.target as HTMLDivElement;
      const scrollBottom = target.scrollHeight - target.scrollTop - target.clientHeight;
      if (scrollBottom < 200 && !loadingMore && hasMore) loadMoreEmails();
    },
    [loadMoreEmails, loadingMore, hasMore],
  );

  const filteredThreads = useMemo(() => {
    let t = [...threads];
    if (selectedAccount !== 'all') {
      const accLower = selectedAccount.toLowerCase();
      t = t.filter((th) => {
        const first = th.messages[0];
        const src = (first.metadata as any)?.source_collection || '';
        const sender = (first.sender || '').toLowerCase();
        const recipient = (first.recipient || '').toLowerCase();

        if (accLower === 'gmax') {
          return (
            sender.includes('gmax') ||
            sender.includes('ellmax.com') ||
            sender.includes('ghislaine') ||
            recipient.includes('gmax') ||
            recipient.includes('ellmax.com') ||
            src.toLowerCase().includes('gmax') ||
            src.toLowerCase().includes('maxwell')
          );
        }
        return src.toLowerCase().includes(accLower) || sender.includes(accLower);
      });
    }
    if (debouncedSearchTerm) {
      const s = debouncedSearchTerm.toLowerCase();
      t = t.filter(
        (th) =>
          th.subject.toLowerCase().includes(s) ||
          th.participantNames.some((p) => p.toLowerCase().includes(s)) ||
          th.snippet.toLowerCase().includes(s),
      );
    }
    t.sort((a, b) => {
      let valA: any, valB: any;
      switch (sortField) {
        case 'date':
          valA = new Date(a.lastMessageDate).getTime();
          valB = new Date(b.lastMessageDate).getTime();
          break;
        case 'sender':
          valA = a.participantNames[0] || '';
          valB = b.participantNames[0] || '';
          break;
        case 'subject':
          valA = a.subject;
          valB = b.subject;
          break;
      }
      if (valA < valB) return sortOrder === 'asc' ? -1 : 1;
      if (valA > valB) return sortOrder === 'asc' ? 1 : -1;
      return 0;
    });
    return t;
  }, [threads, selectedAccount, debouncedSearchTerm, sortField, sortOrder]);

  const selectedThread = useMemo(
    () => threads.find((t) => t.id === selectedThreadId),
    [threads, selectedThreadId],
  );

  const handleSort = (field: SortField) => {
    if (sortField === field) setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc');
    else {
      setSortField(field);
      setSortOrder('desc');
    }
  };

  const formatDate = (dateStr: string) => {
    const date = new Date(dateStr);
    const now = new Date();
    const diff = now.getTime() - date.getTime();
    const days = diff / (1000 * 60 * 60 * 24);
    if (days < 1) return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    if (days < 7) return date.toLocaleDateString([], { weekday: 'short' });
    return date.toLocaleDateString([], { month: 'short', day: 'numeric' });
  };

  const getInitials = (name: string) => {
    const parts = name.split(/[\s@]+/);
    if (parts.length >= 2) return (parts[0][0] + parts[1][0]).toUpperCase();
    return name.slice(0, 2).toUpperCase();
  };

  const getAvatarColor = (name: string) => {
    const colors = [
      'from-blue-500 to-blue-600',
      'from-purple-500 to-purple-600',
      'from-green-500 to-green-600',
      'from-orange-500 to-orange-600',
      'from-pink-500 to-pink-600',
      'from-cyan-500 to-cyan-600',
      'from-red-500 to-red-600',
    ];
    const hash = name.split('').reduce((acc, c) => acc + c.charCodeAt(0), 0);
    return colors[hash % colors.length];
  };

  const handleMailboxSelect = (id: string) => {
    setSelectedAccount(id);
    setShowMailboxDrawer(false);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-64px)] bg-slate-950 md:bg-gradient-to-br md:from-slate-100 md:via-blue-50/30 md:to-purple-50/20 md:dark:from-slate-950 md:dark:via-slate-900 md:dark:to-slate-950 overflow-hidden">
      {/* Mobile Header - iOS Style */}
      <div className="md:hidden flex items-center justify-between px-4 py-3 bg-slate-900 border-b border-slate-800">
        <button
          onClick={() => setShowMailboxDrawer(true)}
          className="flex items-center gap-2 text-blue-400 font-semibold"
        >
          <span className="text-lg">{currentMailbox.label}</span>
          <ChevronDown className="w-4 h-4" />
        </button>
        <div className="text-slate-400 text-sm">{filteredThreads.length.toLocaleString()}</div>
      </div>

      {/* Desktop Sidebar - Hidden on Mobile */}
      {/* Desktop Sidebar - Hidden on Mobile */}
      <div className="flex flex-1 overflow-hidden">
        <aside className="hidden md:flex w-60 flex-col m-3 mr-0 rounded-2xl bg-slate-950/50 backdrop-blur-2xl border border-slate-800 shadow-xl">
          <div className="p-5 pb-3">
            <h2 className="text-[11px] font-bold text-slate-500/80 dark:text-white/40 uppercase tracking-widest">
              Mailboxes
            </h2>
          </div>

          <nav className="flex-1 px-3 space-y-1 overflow-y-auto">
            {mailboxes.map((mb) => (
              <DesktopSidebarItem
                key={mb.id}
                icon={mb.icon}
                label={mb.label}
                count={mb.count}
                active={selectedAccount === mb.id}
                onClick={() => setSelectedAccount(mb.id)}
              />
            ))}
          </nav>

          <div className="p-4 border-t border-slate-800">
            <div className="text-[11px] text-slate-500/70 dark:text-white/30 text-center font-medium">
              {loadedEmails.toLocaleString()} of {totalEmails.toLocaleString()}
            </div>
          </div>
        </aside>

        {/* Main Content Area */}
        <div className="flex-1 flex flex-col md:flex-row md:p-3 md:gap-3 min-w-0">
          {/* Message List */}
          <div
            className={`w-full md:w-[400px] flex flex-col md:rounded-2xl bg-slate-950 md:bg-white/5 md:dark:bg-white/5 md:backdrop-blur-2xl md:border md:border-slate-800 overflow-hidden ${isMobileDetail ? 'hidden md:flex' : 'flex'}`}
          >
            {/* Search Bar - iOS Style */}
            <div className="p-3 bg-slate-900 md:bg-transparent md:p-4 md:border-b md:border-slate-800">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 md:text-slate-400 md:dark:text-white/40" />
                <input
                  type="text"
                  placeholder="Search"
                  className="w-full pl-10 pr-4 py-2 bg-slate-800 md:bg-black/20 md:dark:bg-white/5 rounded-lg text-sm text-white md:text-slate-200 md:dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500/50 placeholder-slate-500 md:placeholder-slate-400 md:dark:placeholder-white/30"
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
              </div>
            </div>

            {/* Gmail-Style Category Tabs */}
            <div className="flex border-b border-slate-800 md:border-slate-800 bg-slate-900/50 md:bg-transparent overflow-x-auto">
              <CategoryTab
                icon={Users}
                label="Primary"
                count={categoryCounts.primary}
                active={activeCategory === 'primary'}
                onClick={() => setActiveCategory('primary')}
                color="blue"
                description="Real people & known entities"
              />
              <CategoryTab
                icon={Bell}
                label="Updates"
                count={categoryCounts.updates}
                active={activeCategory === 'updates'}
                onClick={() => setActiveCategory('updates')}
                color="yellow"
                description="Orders & notifications"
              />
              <CategoryTab
                icon={Tag}
                label="Promotions"
                count={categoryCounts.promotions}
                active={activeCategory === 'promotions'}
                onClick={() => setActiveCategory('promotions')}
                color="green"
                description="Newsletters & marketing"
              />
              <CategoryTab
                icon={Inbox}
                label="All"
                count={categoryCounts.all}
                active={activeCategory === 'all'}
                onClick={() => setActiveCategory('all')}
                color="slate"
                description="Everything"
              />
            </div>

            {/* Sort Header - Hidden on Mobile */}
            <div className="hidden md:flex px-5 py-3 items-center justify-between text-[11px] text-slate-500 dark:text-white/40 border-b border-slate-800 font-semibold uppercase tracking-wide">
              <span>{filteredThreads.length.toLocaleString()} conversations</span>
              <div className="flex items-center gap-4">
                <button
                  onClick={() => handleSort('date')}
                  className={`flex items-center gap-1.5 transition-colors ${sortField === 'date' ? 'text-blue-600 dark:text-blue-400' : 'hover:text-slate-700 dark:hover:text-white/60'}`}
                >
                  <Clock className="w-3.5 h-3.5" /> Date
                </button>
                <button
                  onClick={() => handleSort('sender')}
                  className={`flex items-center gap-1.5 transition-colors ${sortField === 'sender' ? 'text-blue-600 dark:text-blue-400' : 'hover:text-slate-700 dark:hover:text-white/60'}`}
                >
                  <User className="w-3.5 h-3.5" /> From
                </button>
              </div>
            </div>

            {/* Message List */}
            <div ref={listRef} className="flex-1 overflow-y-auto" onScroll={handleScroll}>
              {loading ? (
                <div className="p-10 text-center text-slate-500">
                  <Loader2 className="w-10 h-10 mx-auto mb-4 animate-spin opacity-40" />
                  <div className="font-medium">Loading messages...</div>
                </div>
              ) : (
                <>
                  {filteredThreads.map((thread) => (
                    <IOSMessageRow
                      key={thread.id}
                      thread={thread}
                      selected={selectedThreadId === thread.id}
                      onClick={() => setSelectedThreadId(thread.id)}
                      formatDate={formatDate}
                      getInitials={getInitials}
