import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Newspaper, Search, ChevronDown, ChevronUp, Clock } from 'lucide-react';
import ArticleViewerModal from './ArticleViewerModal';
import { Article } from './ArticleCard';

interface PublicationStats {
  name: string;
  count: number;
  avgRedFlag: number;
}

export const ArticlesTab: React.FC = () => {
  const [articles, setArticles] = useState<Article[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedPublication, setSelectedPublication] = useState<string | null>(null);
  const [viewerArticle, setViewerArticle] = useState<any | null>(null);
  const [showPublicationDropdown, setShowPublicationDropdown] = useState(false);
  const [sortOrder, setSortOrder] = useState<'date' | 'redFlag'>('redFlag');

  const [page, setPage] = useState(1);
  const [hasMore, setHasMore] = useState(false);

  useEffect(() => {
    // Reset and fetch when filters change
    setArticles([]);
    setPage(1);
    fetchArticles(1, true);
  }, [searchTerm, selectedPublication, sortOrder]);

  const fetchArticles = useCallback(
    async (pageNum: number, isReset: boolean = false) => {
      try {
        setLoading(true);
        const params = new URLSearchParams({
          page: pageNum.toString(),
          limit: '12',
          sort: sortOrder,
        });

        if (searchTerm) params.append('search', searchTerm);
        if (selectedPublication) params.append('publication', selectedPublication);

        const response = await fetch(`/api/articles?${params.toString()}`);

        if (!response.ok) {
          console.warn('Articles API not available, using empty array');
          if (isReset) setArticles([]);
          return;
        }

        const { data, pagination } = await response.json();

        if (Array.isArray(data)) {
          // Normalize API response
          const normalized = data.map((item: any) => ({
            id: item.id,
            title: item.title,
            url: item.link || item.url,
            author: item.author || 'Unknown',
            publication: item.source || item.publication || 'Unknown',
            published_date: item.pub_date || item.published_date || '',
            summary: item.description || item.summary || '',
            tags: item.tags || '',
            redFlagRating: item.red_flag_rating ?? item.redFlagRating ?? 0,
            imageUrl: item.image_url || item.imageUrl || null,
            reading_time: item.reading_time || item.readingTime || null,
          }));

          setArticles((prev) => (isReset ? normalized : [...prev, ...normalized]));
          setHasMore(Math.ceil(pagination.total / pagination.limit) > pageNum);
        } else {
          if (isReset) setArticles([]);
        }
      } catch (error) {
        console.error('Error fetching articles:', error);
        if (isReset) setArticles([]);
      } finally {
        setLoading(false);
      }
    },
    [page, searchTerm, selectedPublication, sortOrder],
  );

  const handleLoadMore = () => {
    const nextPage = page + 1;
    setPage(nextPage);
    fetchArticles(nextPage);
  };

  // Calculate publication stats (like albums)
  const publications = useMemo((): PublicationStats[] => {
    const pubMap = new Map<string, { count: number; totalRedFlag: number }>();
    for (const article of articles) {
      const pub = article.publication || 'Unknown';
      const existing = pubMap.get(pub) || { count: 0, totalRedFlag: 0 };
      pubMap.set(pub, {
        count: existing.count + 1,
        totalRedFlag: existing.totalRedFlag + (article.redFlagRating || 0),
      });
    }
    return Array.from(pubMap.entries())
      .map(([name, stats]) => ({
        name,
        count: stats.count,
        avgRedFlag: stats.count > 0 ? stats.totalRedFlag / stats.count : 0,
      }))
      .sort((a, b) => b.count - a.count);
  }, [articles]);

  // Client-side filtering is no longer needed as it's done server-side
  // But we keep the sorting logic if we want to re-sort fetched items,
  // though typically server-side sort is preferred.
  // We'll trust the server order for now or just return 'articles' directly
  // since we reset on sort change.
  const filteredArticles = articles;

  const formatDate = (dateStr: string) => {
    try {
      return new Date(dateStr).toLocaleDateString('en-US', {
        year: 'numeric',
        month: 'short',
        day: 'numeric',
      });
    } catch {
      return dateStr;
    }
  };

  return (
    <div className="flex flex-col h-full min-h-[500px] bg-slate-950 border border-slate-800 shadow-2xl overflow-hidden rounded-lg">
      {/* Header with controls */}
      <div className="bg-slate-900 border-b border-slate-800 flex flex-col md:flex-row md:items-center justify-between px-3 py-2 md:px-4 md:h-14 shrink-0 z-10 gap-2">
        {/* Mobile Publication Dropdown */}
        <div className="md:hidden">
          <button
            onClick={() => setShowPublicationDropdown(!showPublicationDropdown)}
            className="w-full flex items-center justify-between px-3 py-2 bg-slate-800 border border-slate-700 rounded-lg text-white text-sm h-8"
          >
            <span className="flex items-center gap-2">
              <Newspaper className="w-4 h-4" />
              {selectedPublication || 'All Publications'}
            </span>
            {showPublicationDropdown ? (
              <ChevronUp className="w-4 h-4" />
            ) : (
              <ChevronDown className="w-4 h-4" />
            )}
          </button>
          {showPublicationDropdown && (
            <div className="absolute left-3 right-3 mt-1 bg-slate-800 border border-slate-700 rounded-lg shadow-xl z-30 max-h-60 overflow-y-auto">
              <button
                className={`w-full px-4 py-3 text-left text-sm flex items-center justify-between ${!selectedPublication ? 'bg-cyan-900/20 text-cyan-400' : 'text-slate-300 hover:bg-slate-700'}`}
                onClick={() => {
                  setSelectedPublication(null);
                  setShowPublicationDropdown(false);
                }}
              >
                <span>All Publications</span>
                <span className="text-xs opacity-70">{articles.length}</span>
              </button>
              {publications.map((pub) => (
                <button
                  key={pub.name}
                  className={`w-full px-4 py-3 text-left text-sm flex items-center justify-between border-t border-slate-700/50 ${selectedPublication === pub.name ? 'bg-cyan-900/20 text-cyan-400' : 'text-slate-300 hover:bg-slate-700'}`}
                  onClick={() => {
                    setSelectedPublication(pub.name);
                    setShowPublicationDropdown(false);
                  }}
                >
                  <span className="truncate">{pub.name}</span>
                  <span className="text-xs opacity-70">{pub.count}</span>
                </button>
              ))}
            </div>
          )}
        </div>

        {/* Search */}
        <div className="w-full md:w-64 flex gap-2">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 pointer-events-none" />
            <input
              type="text"
              placeholder="Search articles..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full bg-slate-800 border border-slate-700 rounded-lg text-slate-200 pl-9 pr-3 py-2 md:py-1.5 text-sm focus:outline-none focus:ring-1 focus:ring-cyan-500 placeholder-slate-500 transition-all h-8"
            />
          </div>
        </div>

        {/* Desktop Sort Controls */}
        <div className="hidden md:flex items-center gap-3">
          <span className="text-xs text-slate-500 font-medium">Sort by:</span>
          <select
            value={sortOrder}
            onChange={(e) => setSortOrder(e.target.value as 'date' | 'redFlag')}
            className="bg-slate-800 border border-slate-700 rounded text-slate-300 text-xs px-2 py-1 focus:outline-none focus:border-cyan-500 h-8"
          >
            <option value="redFlag">Red Flag Rating</option>
            <option value="date">Date Published</option>
          </select>

          <div className="text-xs text-slate-500">
            {filteredArticles.length} of {articles.length} articles
          </div>
        </div>
      </div>

      <div className="flex flex-1 overflow-hidden relative">
        {/* Publications sidebar - Hidden on mobile */}
        <aside className="hidden md:flex w-60 bg-slate-900 border-r border-slate-800 flex-col shrink-0">
          <h3 className="text-xs font-semibold text-slate-500 uppercase tracking-wider px-4 py-3">
            Publications
          </h3>
          <div className="flex-1 overflow-y-auto">
            <button
              className={`w-full px-4 py-2 text-left text-sm flex items-center justify-between transition-colors ${!selectedPublication ? 'bg-cyan-900/20 text-cyan-400 border-l-2 border-cyan-400' : 'text-slate-400 hover:bg-slate-800 hover:text-white border-l-2 border-transparent'}`}
              onClick={() => setSelectedPublication(null)}
            >
              <span className="truncate">All Publications</span>
              <span className="text-xs opacity-70 bg-slate-800 px-1.5 py-0.5 rounded-full">
                {articles.length}
              </span>
            </button>
            {publications.map((pub) => (
              <button
                key={pub.name}
                className={`w-full px-4 py-2 text-left text-sm flex items-center justify-between transition-colors ${selectedPublication === pub.name ? 'bg-cyan-900/20 text-cyan-400 border-l-2 border-cyan-400' : 'text-slate-400 hover:bg-slate-800 hover:text-white border-l-2 border-transparent'}`}
                onClick={() => setSelectedPublication(pub.name)}
                title={pub.name}
              >
                <span className="truncate">{pub.name}</span>
                <span className="text-xs opacity-70 bg-slate-800 px-1.5 py-0.5 rounded-full">
                  {pub.count}
                </span>
              </button>
            ))}
          </div>
        </aside>

        {/* Main Content */}
        <div className="flex-1 bg-slate-950 flex flex-col overflow-hidden relative">
          {loading ? (
            <div className="absolute inset-0 flex items-center justify-center z-20 bg-slate-950/50 backdrop-blur-sm">
              <div className="animate-spin rounded-full h-8 w-8 border-t-2 border-b-2 border-cyan-500"></div>
            </div>
          ) : null}

          {/* Articles Grid */}
          <div className="flex-1 overflow-y-auto p-4 md:p-6">
            {filteredArticles.length === 0 ? (
              <div className="flex flex-col items-center justify-center h-full text-slate-500">
                <Newspaper className="w-12 h-12 mb-2 opacity-50" />
                <p>No articles found</p>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
                {filteredArticles.map((article) => (
                  <a
                    key={article.id}
                    href={article.url}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="group block bg-slate-900 border border-slate-800 rounded-xl overflow-hidden hover:border-cyan-500/50 hover:shadow-xl hover:shadow-cyan-500/10 transition-all duration-300"
                  >
                    {/* Hero Image */}
                    <div className="aspect-[16/9] relative overflow-hidden bg-gradient-to-br from-slate-800 to-slate-900">
                      {article.imageUrl ? (
                        <img
                          src={article.imageUrl}
                          alt={article.title}
                          className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105"
                          loading="lazy"
                        />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center">
                          <Newspaper className="w-16 h-16 text-slate-700" />
                        </div>
                      )}
                      {/* Gradient overlay */}
                      <div className="absolute inset-0 bg-gradient-to-t from-slate-900 via-transparent to-transparent opacity-60" />
                      {/* Red flag badge */}
                      {article.redFlagRating > 0 && (
                        <div className="absolute top-3 right-3 bg-red-500/90 backdrop-blur-sm px-2 py-1 rounded-full text-xs font-bold text-white flex items-center gap-1">
                          {'🚩'.repeat(Math.min(article.redFlagRating, 5))}
                        </div>
                      )}
                      {/* Publication badge */}
                      <div className="absolute bottom-3 left-3">
                        <span className="px-2.5 py-1 bg-slate-900/80 backdrop-blur-sm text-cyan-400 text-xs font-semibold rounded-full border border-cyan-500/30">
                          {article.publication}
                        </span>
                      </div>
                    </div>

                    {/* Card Content */}
                    <div className="p-5">
                      <h3 className="text-white font-bold text-lg leading-tight group-hover:text-cyan-400 transition-colors mb-2 line-clamp-2">
                        {article.title}
                      </h3>
                      <p className="text-slate-400 text-sm line-clamp-2 mb-4">
                        {article.summary || 'No summary available.'}
                      </p>

                      {/* Author and meta */}
                      <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                          <div className="w-8 h-8 rounded-full bg-gradient-to-br from-cyan-500 to-blue-600 flex items-center justify-center text-white text-xs font-bold">
                            {article.author
                              ?.split(' ')
                              .map((n) => n[0])
                              .join('')
                              .slice(0, 2) || '?'}
                          </div>
                          <div>
                            <div className="text-sm text-white font-medium">
                              {article.author || 'Unknown'}
                            </div>
                            <div className="text-xs text-slate-500">
                              {formatDate(article.published_date)}
                            </div>
                          </div>
                        </div>
                        {article.reading_time && (
                          <div className="flex items-center gap-1 text-xs text-slate-500">
                            <Clock className="w-3 h-3" />
                            {article.reading_time}
                          </div>
                        )}
                      </div>

                      {/* Tags */}
                      {article.tags && (
                        <div className="flex flex-wrap gap-1.5 mt-4 pt-4 border-t border-slate-800">
                          {article.tags
                            .split(',')
                            .slice(0, 4)
                            .map((tag, i) => (
                              <span
                                key={i}
                                className="text-xs px-2 py-0.5 bg-slate-800 text-slate-400 rounded-full hover:bg-slate-700 transition-colors"
                              >
                                {tag.trim()}
                              </span>
                            ))}
                        </div>
                      )}
                    </div>
                  </a>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>

      {hasMore && (
        <div className="p-4 flex justify-center border-t border-slate-800 bg-slate-900/50">
          <button
            onClick={handleLoadMore}
            disabled={loading}
            className="px-6 py-2 bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-lg transition-colors border border-slate-700 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
          >
            {loading ? (
              <>
                <div className="w-4 h-4 border-2 border-slate-400 border-t-transparent rounded-full animate-spin" />
                Loading...
              </>
            ) : (
              'Load More Articles'
            )}
          </button>
        </div>
      )}

      <ArticleViewerModal
        article={viewerArticle}
        highlight={searchTerm}
        onClose={() => setViewerArticle(null)}
      />
    </div>
  );
};

export default ArticlesTab;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { FixedSizeList as List } from 'react-window';
import { AudioPlayer, TranscriptSegment, Chapter } from './AudioPlayer';
import { Music, CheckSquare, Square, Clock, Calendar } from 'lucide-react';
import { SensitiveContent } from '../common/SensitiveContent';
import BatchToolbar from '../common/BatchToolbar';
import { SensitiveWarningBanner } from '../shared/SensitiveWarningBanner';
import Icon from '../common/Icon';

interface AudioItem {
  id: number;
  title: string;
  description?: string;
  filePath: string;
  fileType: string;
  isSensitive: boolean;
  documentId?: number;
  albumId?: number;
  albumName?: string;
  metadata: {
    duration?: number;
    transcript?: TranscriptSegment[];
    chapters?: Chapter[];
    [key: string]: any;
  };
  createdAt: string;
  entityName?: string;
  entityId?: number;
  tags?: Array<{ id: number; name: string }>;
  people?: Array<{ id: number; name: string }>;
}

interface Album {
  id: number;
  name: string;
  description?: string;
  itemCount: number;
  sensitiveCount?: number;
}

interface AudioBrowserProps {
  initialAlbumId?: number;
  initialAudioId?: number;
  initialTimestamp?: number;
  quickStart?: boolean;
}

export const AudioBrowser: React.FC<AudioBrowserProps> = ({
  initialAlbumId,
  initialAudioId,
  initialTimestamp,
  quickStart = false,
}) => {
  const [items, setItems] = useState<AudioItem[]>([]);
  const [albums, setAlbums] = useState<Album[]>([]);
  const [selectedAlbum, setSelectedAlbum] = useState<number | null>(null);
  const [selectedItem, setSelectedItem] = useState<AudioItem | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [page, setPage] = useState(1);
  const [hasMore, setHasMore] = useState(true);
  const [_coverTick, setCoverTick] = useState(0);
  const [libraryTotalCount, setLibraryTotalCount] = useState(0);
  const [showAlbumDropdown, setShowAlbumDropdown] = useState(false);
  const [investigationId, setInvestigationId] = useState<number | null>(null);
  const [investigationSummary, setInvestigationSummary] = useState<any | null>(null);
  const [pickerOpenId, setPickerOpenId] = useState<number | null>(null);
  const [investigationsList, setInvestigationsList] = useState<any[]>([]);
  const [addingId, setAddingId] = useState<number | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  // Transcript search (within album or across all audio)
  const [transcriptSearch, setTranscriptSearch] = useState('');
  // Optional timecode from URL (e.g. shared links)
  const [initialUrlTimestamp, setInitialUrlTimestamp] = useState<number | undefined>(
    initialTimestamp,
  );

  // Batch Mode State
  const [isBatchMode, setIsBatchMode] = useState(false);
  const [selectedItems, setSelectedItems] = useState<Set<number>>(new Set());

  const currentAlbum = useMemo(
    () => albums.find((a) => a.id === selectedAlbum),
    [albums, selectedAlbum],
  );

  // Effect to select album when loaded if initialAlbumId is provided
  useEffect(() => {
    if (initialAlbumId && albums.length > 0 && selectedAlbum === null) {
      const match = albums.find((a) => a.id === initialAlbumId);
      if (match) {
        console.log(`Selecting requested album: ${match.name} (${match.id})`);
        setSelectedAlbum(match.id);
      }
    }
  }, [initialAlbumId, albums, selectedAlbum]);

  // Effect to load specific item if requested via URL or props
  useEffect(() => {
    const url = new URL(window.location.href);
    const urlId = url.searchParams.get('id');
    const urlT = url.searchParams.get('t');

    const targetId = initialAudioId || (urlId ? parseInt(urlId, 10) : undefined);
    const targetT =
      initialTimestamp !== undefined
        ? initialTimestamp
        : urlT && !Number.isNaN(parseInt(urlT, 10))
          ? parseInt(urlT, 10)
          : undefined;

    if (targetT !== undefined && initialUrlTimestamp === undefined) {
      setInitialUrlTimestamp(targetT);
    }

    if (targetId && !selectedItem) {
      // Fetch the specific item
      fetch(`/api/media/audio/${targetId}`)
        .then((res) => res.json())
        .then((data) => {
          if (data && data.id) {
            console.log('Loaded direct link item:', data.title);
            const item = {
              ...data,
              metadata:
                typeof data.metadata === 'string' ? JSON.parse(data.metadata) : data.metadata,
            };
            setSelectedItem(item);
          }
        })
        .catch(console.error);
    }
  }, [initialAudioId, initialTimestamp, selectedItem, initialUrlTimestamp]);

  // Load albums on mount
  useEffect(() => {
    loadAlbums();
    return () => abortControllerRef.current?.abort();
  }, []);

  useEffect(() => {
    const id = setInterval(() => {
      setCoverTick((t) => (t + 1) % 2);
    }, 12000);
    return () => clearInterval(id);
  }, []);

  useEffect(() => {
    const loadTotals = async () => {
      try {
        const res = await fetch('/api/media/audio?page=1&limit=1');
        if (res.ok) {
          const json = await res.json();
          if (typeof json?.total === 'number') setLibraryTotalCount(json.total);
        }
      } catch {
        void 0;
      }
    };
    loadTotals();
  }, []);
  // Load items when album selection or transcript search changes
  useEffect(() => {
    fetchAudio(1);
    // eslint-disable-next-line react-hooks/exhaustive-deps -- fetchAudio already captures latest selectedAlbum/transcriptSearch
  }, [selectedAlbum, transcriptSearch]);

  useEffect(() => {
    const isSascha =
      (currentAlbum && currentAlbum.name.includes('Sascha')) ||
      items.some((it) => it.title.includes('Sascha'));
    if (!isSascha) {
      setInvestigationId(null);
      setInvestigationSummary(null);
      return;
    }
    (async () => {
      try {
        const resp = await fetch(
          `/api/investigations/by-title?title=${encodeURIComponent('Sascha Barros Testimony')}`,
        );
        if (resp.ok) {
          const inv = await resp.json();
          setInvestigationId(inv.id);
          const sumResp = await fetch(`/api/investigation/${inv.id}/evidence-summary`);
          if (sumResp.ok) {
            const summary = await sumResp.json();
            setInvestigationSummary(summary);
          }
        }
      } catch {
        void 0;
      }
    })();
  }, [currentAlbum, items]);

  const loadAlbums = async () => {
    try {
      const res = await fetch('/api/media/audio/albums');
      if (!res.ok) throw new Error('Failed to load albums');
      const data = await res.json();
      setAlbums(data);
    } catch (err) {
      console.error('Failed to load albums:', err);
    }
  };

  // Batch Handlers
  const toggleSelection = useCallback(
    (id: number) => {
      const newSet = new Set(selectedItems);
      if (newSet.has(id)) newSet.delete(id);
      else newSet.add(id);
      setSelectedItems(newSet);
    },
    [selectedItems],
  );

  const handleBatchTag = async (tagIds: number[], action: 'add' | 'remove') => {
    try {
      await fetch('/api/media/items/batch/tags', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ itemIds: Array.from(selectedItems), tagIds, action }),
      });
      // Refresh data to show new tags
      fetchAudio(1);
      setSelectedItems(new Set());
      setIsBatchMode(false);
    } catch (e) {
      console.error(e);
    }
  };

  const handleBatchPeople = async (personIds: number[]) => {
    try {
      await fetch('/api/media/items/batch/people', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ itemIds: Array.from(selectedItems), personIds, action: 'add' }),
      });
      fetchAudio(1);
      setSelectedItems(new Set());
      setIsBatchMode(false);
    } catch (e) {
      console.error(e);
    }
  };

  const fetchAudio = useCallback(
    async (pageNum: number) => {
      try {
        setLoading(true);

        // Abort previous request
        if (abortControllerRef.current) {
          abortControllerRef.current.abort();
        }
        abortControllerRef.current = new AbortController();

        const params = new URLSearchParams({
          page: pageNum.toString(),
          limit: '24',
        });
        if (selectedAlbum) {
          params.append('albumId', selectedAlbum.toString());
        }
        if (transcriptSearch.trim()) {
          params.append('transcriptQuery', transcriptSearch.trim());
        }
        // Always sort by title as requested ("sorted by name by tranche")
        params.append('sortBy', 'title');

        const res = await fetch(`/api/media/audio?${params}`, {
          signal: abortControllerRef.current.signal,
        });
        if (!res.ok) throw new Error('Failed to load audio files');

        const data = await res.json();
        const newItems = data.mediaItems || [];

        if (pageNum === 1) {
          setItems(newItems);
        } else {
          setItems((prev) => [...prev, ...newItems]);
        }

        if (pageNum === 1 && quickStart && !selectedItem && newItems.length > 0) {
          setSelectedItem(newItems[0]);
        }

        setHasMore(newItems.length === 24);
        setPage(pageNum);
      } catch (err) {
        if (err instanceof Error && err.name === 'AbortError') return;
        console.error(err);
        setError('Failed to load audio content');
      } finally {
        setLoading(false);
      }
    },
    [selectedAlbum, transcriptSearch, quickStart, selectedItem],
  );

  const handleLoadMore = useCallback(() => {
    const nextPage = page + 1;
    fetchAudio(nextPage);
  }, [page, fetchAudio]);

  const formatDate = useCallback((dateStr: string) => {
    return new Date(dateStr).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric',
    });
  }, []);

  // Virtualization setup
  const containerRef = useRef<HTMLDivElement>(null);
  const [containerWidth, setContainerWidth] = useState(0);

  // Measure container width for responsive grid calculation
  useEffect(() => {
    if (!containerRef.current) return;
    const observer = new ResizeObserver((entries) => {
      setContainerWidth(entries[0].contentRect.width);
    });
    observer.observe(containerRef.current);
    return () => observer.disconnect();
  }, []);

  // Calculate columns dynamically based on available width
  const columns = useMemo(() => {
    if (containerWidth === 0) return 1;
    // Aim for a 3-column layout by default on typical desktop widths,
    // similar to the video browser grid. Use a smaller min card width
    // to keep cards reasonably compact while still accommodating
    // multi-line transcript previews.
    const gap = 24; // gap-6
    const padding = 48; // px-6 * 2
    const minCardWidth = 260;
    const available = containerWidth - padding;
    const rawCols = Math.floor((available + gap) / (minCardWidth + gap));
    const cols = Math.max(1, rawCols);
    return cols;
  }, [containerWidth]);

  const rowCount = Math.ceil(items.length / columns);
  // Items are always considered loadable while hasMore is true; InfiniteLoader only
  // cares that loadMoreItems resolves when there's nothing left to fetch.
  // InfiniteLoader compatibility helper; kept for clarity even if not currently wired
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const isItemLoaded = (_index: number) => _index < rowCount;
  const loadMoreItems = useCallback(
    (_startIndex: number, _stopIndex: number) => {
      if (!loading && hasMore) {
        return handleLoadMore();
      }
      return Promise.resolve();
    },
    [loading, hasMore, handleLoadMore],
  );

  const showSensitiveWarning =
    currentAlbum &&
    (currentAlbum.name.match(/Sensitive|Disturbing|Testimony|Victim|Survivor/i) ||
      (currentAlbum.sensitiveCount && currentAlbum.sensitiveCount > 0));

  // Row renderer for virtualized list
  const Row = useCallback(
    ({ index, style }: { index: number; style: React.CSSProperties }) => {
      const startIdx = index * columns;
      const rowItems = items.slice(startIdx, startIdx + columns);

      // Manual padding offset: Shift top down by 24px (py-6 top)
      const adjustedStyle = {
        ...style,
        top: (typeof style.top === 'number' ? style.top : parseFloat(style.top as string)) + 24,
        height:
          typeof style.height === 'number' ? style.height : parseFloat(style.height as string),
      };

      return (
        <div style={adjustedStyle} className="px-6">
          <div
            className="grid gap-6 pb-6"
            style={{
              gridTemplateColumns: `repeat(${columns}, minmax(0, 1fr))`,
            }}
          >
            {rowItems.map((item) => {
              const isSelected = selectedItems.has(item.id);
              const isSascha =
                item.title.includes('Sascha') ||
                (item.albumName && item.albumName.includes('Sascha'));
              const thumb = item.metadata?.thumbnailPath || null;
              const displayImage = thumb
                ? `/api/static?path=${encodeURIComponent(thumb)}`
                : isSascha
                  ? `/data/media/audio/lvoocaudiop1/lvoocaudiop1.webp`
                  : null;

              return (
                <div
                  key={item.id}
                  className={`bg-slate-900/50 border rounded-lg overflow-hidden transition-all group cursor-pointer flex flex-col min-h-[260px] ${isSelected ? 'border-cyan-500 ring-1 ring-cyan-500' : 'border-slate-800 hover:border-cyan-500/30'}`}
                  onClick={(_e) => {
                    if (isBatchMode) {
                      toggleSelection(item.id);
                    } else {
                      setSelectedItem(item);
                    }
                  }}
                >
                  <SensitiveContent isSensitive={false} className="relative shrink-0">
                    <div className="absolute top-2 right-2 z-30 flex items-center gap-2">
                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          setPickerOpenId(pickerOpenId === item.id ? null : item.id);
                          if (investigationsList.length === 0) {
                            fetch('/api/investigations?page=1&limit=50')
                              .then((r) => r.json())
                              .then((data) => {
                                const list = Array.isArray(data?.data)
                                  ? data.data
                                  : Array.isArray(data)
                                    ? data
                                    : [];
                                setInvestigationsList(list);
                              })
                              .catch(() => {});
                          }
                        }}
                        className="w-6 h-6 flex items-center justify-center rounded bg-amber-700 text-white text-[11px] font-bold border border-amber-500"
                      >
                        +
                      </button>
                      {pickerOpenId === item.id && (
                        <div className="bg-slate-900 border border-slate-700 rounded p-2 shadow-xl">
                          <select
                            onChange={async (e) => {
                              const invId = parseInt(e.target.value);
                              if (!invId) return;
                              setAddingId(item.id);
                              try {
                                const res = await fetch('/api/investigation/add-media', {
                                  method: 'POST',
                                  headers: { 'Content-Type': 'application/json' },
                                  body: JSON.stringify({
                                    investigationId: invId,
                                    mediaItemId: item.id,
                                    notes: '',
                                    relevance: 'high',
                                  }),
                                });
                                if (res.ok) {
                                  setPickerOpenId(null);
                                }
                              } finally {
                                setAddingId(null);
                              }
                            }}
                            className="text-xs bg-slate-800 text-white border border-slate-700 rounded px-2 py-1"
                          >
                            <option value="">Select investigation</option>
                            <option value={investigationId || ''}>
                              {investigationId ? 'Sascha Barros Testimony' : 'Default'}
                            </option>
                            {investigationsList.map((inv: any) => (
                              <option key={inv.id} value={inv.id}>
                                {inv.title}
                              </option>
                            ))}
                          </select>
                        </div>
                      )}
                      {addingId === item.id && (
                        <div className="text-[10px] text-white bg-black/60 px-2 py-0.5 rounded">
                          …
                        </div>
                      )}
                    </div>
                    {isBatchMode && (
                      <div className="absolute top-2 left-2 z-20">
                        {isSelected ? (
                          <CheckSquare className="text-cyan-500 fill-cyan-950" />
                        ) : (
                          <Square className="text-white/70" />
                        )}
                      </div>
                    )}
                    <div className="aspect-video bg-slate-900 relative flex items-center justify-center group-hover:bg-slate-800 transition-colors overflow-hidden">
                      {displayImage ? (
                        <img
                          src={displayImage}
                          alt="Album Art"
                          className="w-full h-full object-cover opacity-80 group-hover:opacity-100 group-hover:scale-105 transition-all duration-500"
                          onError={(e) => {
                            const t = e.currentTarget;
                            const tried = t.getAttribute('data-fb') === '1';
                            if (!tried) {
                              t.setAttribute('data-fb', '1');
                              const u = new URL(t.src, window.location.origin);
                              const p = u.searchParams.get('path') || '';
                              const next = p.endsWith('.jpg')
                                ? p.replace('.jpg', '.webp')
                                : p.replace('.webp', '.jpg');
                              t.src = `/api/static?path=${encodeURIComponent(next)}`;
                            } else {
                              t.src = 'data:image/gif;base64,R0lGODlhAQABAAD/ACwAAAAAAQABAAACADs=';
                            }
                          }}
                        />
                      ) : (
                        <div className="w-16 h-16 rounded-full bg-slate-800 flex items-center justify-center border border-slate-700 group-hover:scale-110 transition-transform shadow-lg">
                          <Music size={32} className="text-cyan-500" />
                        </div>
                      )}

                      {item.metadata.duration > 0 && (
                        <div className="absolute bottom-2 right-2 px-2 py-1 bg-black/80 text-white text-xs rounded-full font-mono flex items-center gap-1">
                          <Clock size={10} />
                          {Math.floor(item.metadata.duration / 60)}:
                          {(item.metadata.duration % 60).toString().padStart(2, '0')}
                        </div>
                      )}
                    </div>
                  </SensitiveContent>

                  <div className="p-4 flex-1 flex flex-col">
                    <div className="flex items-start justify-between gap-2 mb-2">
                      <h3
                        className="font-medium text-slate-200 group-hover:text-cyan-400 transition-colors line-clamp-2"
                        title={item.title}
                      >
                        {item.title}
                      </h3>
                    </div>

                    <div className="flex flex-wrap gap-1 mb-2">
                      {item.tags &&
                        item.tags.map((t: any) => (
                          <span
                            key={t.id}
                            className="text-[10px] bg-slate-800 text-cyan-400 px-1.5 py-0.5 rounded-full"
                          >
                            {t.name}
                          </span>
                        ))}
                      {item.people &&
                        item.people.map((p: any) => (
                          <span
                            key={p.id}
                            className="text-[10px] bg-slate-800 text-amber-400 px-1.5 py-0.5 rounded-full"
                          >
                            {p.name}
                          </span>
                        ))}
                    </div>

                    <div className="mt-auto space-y-2">
                      <div className="flex items-center gap-2 text-xs text-slate-500">
                        <Calendar size={12} />
                        <span>{formatDate(item.createdAt)}</span>
                      </div>
                      {item.description && (
                        <p className="text-xs text-slate-400 line-clamp-6">{item.description}</p>
                      )}

                      {/* When transcriptSearch is active, surface matching transcript
                          segments here so users see what text is being matched and
                          can jump straight to the relevant timecodes. */}
                      {transcriptSearch.trim() &&
                        Array.isArray(item.metadata?.transcript) &&
                        item.metadata.transcript.length > 0 && (
                          <div className="mt-3 border-t border-slate-800 pt-2 space-y-1 min-h-[60px]">
                            <p className="text-[10px] uppercase tracking-wide text-slate-500">
                              Transcript matches
                            </p>
                            {item.metadata.transcript
                              .map((seg: TranscriptSegment, idx: number) => ({ seg, idx }))
                              .filter(({ seg }) =>
                                (seg.text || '')
                                  .toLowerCase()
                                  .includes(transcriptSearch.trim().toLowerCase()),
                              )
                              .slice(0, 3)
                              .map(({ seg }, matchIdx) => {
                                const query = transcriptSearch.trim();
                                const lower = (seg.text || '').toLowerCase();
                                const q = query.toLowerCase();
                                let preview: React.ReactNode = seg.text;
                                if (q && lower.includes(q)) {
                                  const startIdx = lower.indexOf(q);
                                  const endIdx = startIdx + q.length;
                                  const before = seg.text.slice(0, startIdx);
                                  const matchText = seg.text.slice(startIdx, endIdx);
                                  const after = seg.text.slice(endIdx);
                                  preview = (
                                    <>
                                      {before}
                                      <mark className="bg-amber-500/40 text-inherit px-0.5 rounded-sm">
                                        {matchText}
                                      </mark>
                                      {after}
                                    </>
                                  );
                                }
                                return (
                                  <button
                                    key={matchIdx}
                                    type="button"
                                    className="w-full text-left text-[11px] text-slate-300 hover:text-cyan-300 hover:bg-slate-800/60 rounded px-2 py-1 flex items-start gap-2"
                                    onClick={(e) => {
                                      e.stopPropagation();
                                      // Open this item at the segment start time.
                                      setSelectedItem(item);
                                      const url = new URL(window.location.href);
                                      url.searchParams.set('id', item.id.toString());
                                      url.searchParams.set(
                                        't',
                                        Math.floor(seg.start || 0).toString(),
                                      );
                                      window.history.pushState({}, '', url.toString());
                                    }}
                                  >
                                    <span className="font-mono text-[10px] text-slate-500 min-w-[40px]">
                                      {Math.floor((seg.start || 0) / 60)}:
                                      {Math.floor((seg.start || 0) % 60)
                                        .toString()
                                        .padStart(2, '0')}
                                    </span>
                                    <span className="flex-1 line-clamp-2">{preview}</span>
                                  </button>
                                );
                              })}
                          </div>
                        )}
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      );
    },
    [
      items,
      columns,
      selectedItems,
      isBatchMode,
      formatDate,
      toggleSelection,
      pickerOpenId,
      investigationsList,
      addingId,
      investigationId,
      transcriptSearch,
    ],
  );

  // Update URL when item or album is selected
  useEffect(() => {
    const url = new URL(window.location.href);

    if (selectedItem) {
      url.searchParams.set('id', selectedItem.id.toString());
    } else {
      url.searchParams.delete('id');
    }

    if (selectedAlbum) {
      url.searchParams.set('albumId', selectedAlbum.toString());
    } else {
      url.searchParams.delete('albumId');
    }

    window.history.pushState({}, '', url.toString());
  }, [selectedItem, selectedAlbum]);

  return (
    <div className="flex flex-col h-full min-h-[500px] bg-slate-950 border border-slate-800 shadow-2xl overflow-hidden rounded-lg">
      {/* Header */}
      <div className="bg-slate-900 border-b border-slate-800 px-6 py-4 flex flex-col gap-4 md:flex-row md:items-center md:justify-between shrink-0 z-10">
        <div className="flex flex-col gap-1">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-lg bg-cyan-500/10 border border-cyan-500/20 flex items-center justify-center text-cyan-400">
              <Music size={20} />
            </div>
            <div>
              <h2 className="text-xl font-bold text-white tracking-tight">Audio Recordings</h2>
              <p className="text-slate-400 text-xs font-medium">
                Forensic audio evidence and transcripts
              </p>
            </div>
          </div>

          {investigationSummary && (
            <div className="mt-2 flex flex-wrap items-center gap-2">
              <div className="flex items-center gap-1.5 px-3 py-1 rounded-md bg-amber-900/30 text-amber-300 border border-amber-500/30 text-[11px] font-bold uppercase tracking-wider">
                <Icon name="Database" size="xs" />
                <span>Evidence {investigationSummary.totalEvidence}</span>
              </div>
              <div className="flex items-center gap-1.5 px-3 py-1 rounded-md bg-green-900/30 text-green-300 border border-green-500/30 text-[11px] font-bold uppercase tracking-wider">
                <Icon name="Shield" size="xs" />
                <span>
                  High{' '}
                  {
                    (investigationSummary.evidence || []).filter((e: any) => e.relevance === 'high')
                      .length
                  }
                </span>
              </div>
              <div className="flex items-center gap-1.5 px-3 py-1 rounded-md bg-blue-900/30 text-blue-300 border border-blue-500/30 text-[11px] font-bold uppercase tracking-wider">
                <Icon name="Check" size="xs" />
                <span>
                  Medium{' '}
                  {
                    (investigationSummary.evidence || []).filter(
                      (e: any) => e.relevance === 'medium',
                    ).length
                  }
                </span>
              </div>
              <div className="flex items-center gap-1.5 px-3 py-1 rounded-md bg-slate-800/60 text-slate-400 border border-slate-700/50 text-[11px] font-bold uppercase tracking-wider">
                <Icon name="Info" size="xs" />
                <span>
                  Low{' '}
                  {
                    (investigationSummary.evidence || []).filter((e: any) => e.relevance === 'low')
                      .length
                  }
                </span>
              </div>
            </div>
          )}
        </div>

        <div className="flex items-center gap-3">
          {/* Transcript search */}
          <div className="relative w-64">
            <Icon
              name="Search"
              size="sm"
              className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 pointer-events-none"
            />
            <input
              type="text"
              value={transcriptSearch}
              onChange={(e) => setTranscriptSearch(e.target.value)}
              placeholder={
                selectedAlbum ? 'Search transcripts in this album…' : 'Search transcripts…'
              }
              className="w-full bg-slate-950 border border-slate-800 rounded-lg text-slate-200 pl-9 pr-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-cyan-500/50 placeholder-slate-600 transition-all border-hover:slate-700"
            />
          </div>

          <div className="h-8 w-[1px] bg-slate-800 mx-1 hidden md:block"></div>

          <button
            onClick={() => setIsBatchMode(!isBatchMode)}
            className={`px-4 py-2 rounded-lg text-xs font-bold uppercase tracking-wider transition-all shadow-lg ${
              isBatchMode
                ? 'bg-cyan-600 text-white ring-2 ring-cyan-400/30'
                : 'bg-slate-800 text-slate-400 hover:text-white hover:bg-slate-700 border border-slate-700'
            }`}
          >
            {isBatchMode ? 'Exit Batch' : 'Batch Edit'}
          </button>

          <button
            onClick={async () => {
              try {
                const resp = await fetch(
                  `/api/investigations/by-title?title=${encodeURIComponent('Sascha Barros Testimony')}`,
                );
                if (resp.ok) {
                  const inv = await resp.json();
                  window.location.href = `/investigations/${inv.id}`;
                }
              } catch {
                void 0;
              }
            }}
            className="px-4 py-2 rounded-lg text-xs font-bold uppercase tracking-wider bg-gradient-to-r from-amber-600 to-amber-700 hover:from-amber-500 hover:to-amber-600 text-white border border-amber-500/50 shadow-lg shadow-amber-900/20 active:scale-95 transition-all flex items-center gap-2"
          >
            <Icon name="ExternalLink" size="xs" />
            <span>Open Investigation</span>
          </button>
        </div>
      </div>

      <div className="flex flex-1 overflow-hidden relative">
        {/* Albums sidebar - Hidden on mobile */}
        <aside className="hidden md:flex w-60 bg-slate-900 border-r border-slate-800 flex-col shrink-0">
          <h3 className="text-xs font-semibold text-slate-500 uppercase tracking-wider px-4 py-3">
            Albums
          </h3>
          <div className="flex-1 overflow-y-auto">
            <button
              className={`w-full px-4 py-2 text-left text-sm flex items-center justify-between transition-colors ${selectedAlbum === null ? 'bg-cyan-900/20 text-cyan-400 border-l-2 border-cyan-400' : 'text-slate-400 hover:bg-slate-800 hover:text-white border-l-2 border-transparent'}`}
              onClick={() => setSelectedAlbum(null)}
            >
              <span className="truncate">All Audio</span>
              <span className="text-xs opacity-70 bg-slate-800 px-1.5 py-0.5 rounded-full">
                {libraryTotalCount}
              </span>
            </button>
            {albums.map((album) => (
              <button
                key={album.id}
                className={`w-full px-4 py-2 text-left text-sm flex items-center justify-between transition-colors ${selectedAlbum === album.id ? 'bg-cyan-900/20 text-cyan-400 border-l-2 border-cyan-400' : 'text-slate-400 hover:bg-slate-800 hover:text-white border-l-2 border-transparent'}`}
                onClick={() => setSelectedAlbum(album.id)}
                title={album.name}
              >
                <span className="truncate">{album.name}</span>
                <span className="text-xs opacity-70 bg-slate-800 px-1.5 py-0.5 rounded-full">
                  {album.itemCount || 0}
                </span>
              </button>
            ))}
          </div>
        </aside>

        {/* Main Content */}
        <div className="flex-1 bg-slate-950 flex flex-col overflow-hidden">
          {loading && page === 1 ? (
            <div className="absolute inset-0 flex items-center justify-center z-20 bg-slate-950/50 backdrop-blur-sm">
              <div className="animate-spin rounded-full h-8 w-8 border-t-2 border-b-2 border-cyan-500"></div>
            </div>
          ) : null}

          {/* Sensitive Content Warning Banner */}
          {showSensitiveWarning && <SensitiveWarningBanner mediaType="audio" />}

          {error && (
            <div className="bg-red-900/20 border border-red-500/50 text-red-200 p-4 mx-6 mt-6 rounded-lg">
              {error}
            </div>
          )}

          <div ref={containerRef} className="flex-1 overflow-hidden">
            {items.length === 0 && !loading ? (
              <div className="flex flex-col items-center justify-center h-full text-slate-500">
                <Icon name="Music" size="lg" className="mb-2 opacity-50" />
                <p>No audio recordings found</p>
              </div>
            ) : containerWidth > 0 ? (
              <div className="h-full flex flex-col">
                <List
                  height={containerRef.current?.clientHeight || 600}
                  itemCount={rowCount}
                  itemSize={440}
                  width="100%"
                  overscanCount={2}
                  className="scrollbar-thin scrollbar-thumb-slate-700 scrollbar-track-transparent"
                  innerElementType={React.forwardRef<HTMLDivElement, any>(
                    ({ style, ...rest }, ref) => (
                      <div
                        ref={ref}
                        style={{
                          ...style,
                          height: `${parseFloat(style.height) + 48}px`, // +24px top, +24px bottom
                        }}
                        {...rest}
                      />
                    ),
                  )}
                  onScroll={({ scrollOffset, scrollUpdateWasRequested }) => {
                    if (scrollUpdateWasRequested) return;
                    const containerHeight = containerRef.current?.clientHeight || 600;
                    const totalHeight = rowCount * 520;
                    if (
                      scrollOffset + containerHeight >= totalHeight - 200 &&
                      !loading &&
                      hasMore
                    ) {
                      loadMoreItems(0, 0);
                    }
                  }}
                >
                  {Row}
                </List>
                {loading && (
                  <div className="py-4 flex items-center justify-center">
                    <div className="animate-spin rounded-full h-6 w-6 border-t-2 border-b-2 border-cyan-500"></div>
                  </div>
                )}
              </div>
            ) : null}
          </div>
        </div>
      </div>

      {/* Footer Status Bar */}
      <div className="h-6 bg-slate-900 border-t border-slate-800 flex items-center justify-between px-3 text-[10px] text-slate-500 select-none shrink-0">
        <div>{items.length} items</div>
        <div>{selectedAlbum ? currentAlbum?.name : 'All Audio'}</div>
      </div>

      {/* Batch Toolbar */}
      {isBatchMode && selectedItems.size > 0 && (
        <div className="fixed bottom-6 left-1/2 transform -translate-x-1/2 z-50 w-full max-w-4xl px-4">
          <BatchToolbar
            selectedCount={selectedItems.size}
            onRotate={() => {}}
            onAssignTags={(tags) => handleBatchTag(tags, 'add')}
            onAssignPeople={handleBatchPeople}
            onAssignRating={() => {}}
            onEditMetadata={() => {}}
            onCancel={() => setSelectedItems(new Set())}
            onDeselect={() => setSelectedItems(new Set())}
          />
        </div>
      )}

      {/* Audio Player Modal */}
      {selectedItem &&
        createPortal(
          <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 md:p-8 animate-in fade-in duration-200">
            <div className="w-full max-w-5xl h-[80vh] shadow-2xl ring-1 ring-white/10 rounded-lg overflow-hidden">
              <AudioPlayer
                key={selectedItem.id}
                src={`/api/media/audio/${selectedItem.id}/stream`}
                title={selectedItem.title}
                transcript={selectedItem.metadata.transcript}
                chapters={selectedItem.metadata.chapters}
                autoPlay
                isSensitive={selectedItem.isSensitive}
                warningText={selectedItem.description}
                documentId={selectedItem.id}
                initialTime={
                  initialUrlTimestamp !== undefined &&
                  selectedItem.id === (initialAudioId || selectedItem.id)
                    ? initialUrlTimestamp
                    : 0
                }
                albumImages={
                  selectedItem.title.includes('Sascha') ||
                  (selectedItem.albumName && selectedItem.albumName.includes('Sascha')) ||
                  (currentAlbum && currentAlbum.name.includes('Sascha'))
                    ? [
                        '/data/media/audio/lvoocaudiop1/lvoocaudiop1.webp',
                        '/data/media/audio/lvoocaudiop1/lvoocaudiop1.jpg',
                      ]
                    : []
                }
                onClose={() => {
                  setSelectedItem(null);
                  // Clear URL params but keep album if selected
                  const url = new URL(window.location.href);
                  url.searchParams.delete('id');
                  url.searchParams.delete('t');
                  window.history.pushState({}, '', url.toString());
                }}
              />
            </div>
          </div>,
          document.body,
        )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import {
  Network,
  FileText,
  Search,
  Download,
  Settings,
  Sliders,
  Filter,
  Users,
  Shield,
  Zap,
  Info,
  ChevronRight,
  AlertTriangle,
} from 'lucide-react';

export interface NetworkNode {
  id: string;
  type: 'person' | 'document' | 'organization' | 'location' | 'event' | 'evidence';
  label: string;
  description?: string;
  importance: number; // 1-5 scale
  metadata: {
    mentions?: number;
    documents?: string[];
    connections?: string[];
    category?: string;
    riskLevel?: 'low' | 'medium' | 'high' | 'critical';
    evidenceStrength?: 'weak' | 'moderate' | 'strong' | 'crucial';
  };
  position?: { x: number; y: number };
  color?: string;
  size?: number;
}

export interface NetworkEdge {
  id: string;
  source: string;
  target: string;
  type: 'connection' | 'communication' | 'financial' | 'legal' | 'family' | 'business' | 'evidence';
  strength: number; // 1-10 scale
  direction?: 'unidirectional' | 'bidirectional';
  metadata: {
    frequency?: number;
    dates?: string[];
    context?: string;
    evidence?: string[];
    confidence?: number;
    was_agentic?: boolean;
    ingestRunId?: string;
  };
}

export interface NetworkVisualizationProps {
  nodes: NetworkNode[];
  edges: NetworkEdge[];
  onNodeClick?: (node: NetworkNode) => void;
  onEdgeClick?: (edge: NetworkEdge) => void;
  selectedNodeId?: string;
  selectedEdgeId?: string;
  showFilters?: boolean;
  showLegend?: boolean;
  interactive?: boolean;
  height?: number;
}

export const NetworkVisualization: React.FC<NetworkVisualizationProps> = ({
  nodes: initialNodes,
  edges: initialEdges,
  onNodeClick,
  onEdgeClick,
  selectedNodeId,
  selectedEdgeId,
  // showFilters/showLegend removed from destructuring (unused)
  interactive = true,
  height = 600,
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [nodes, setNodes] = useState<NetworkNode[]>([]);
  const [edges, setEdges] = useState<NetworkEdge[]>([]);
  const [filteredNodes, setFilteredNodes] = useState<NetworkNode[]>([]);
  const [filteredEdges, setFilteredEdges] = useState<NetworkEdge[]>([]);

  const [searchTerm, setSearchTerm] = useState('');
  // filterType/Risk removed (unused)
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });
  const [zoom, setZoom] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [lastPan, setLastPan] = useState({ x: 0, y: 0 });
  const [damningEvidenceOnly, setDamningEvidenceOnly] = useState(false);
  const [showTableView, setShowTableView] = useState(false);
  const [showSettings, setShowSettings] = useState(true);
  const [minStrength, setMinStrength] = useState(0);
  const [maxHops, setMaxHops] = useState(3);
  const [rootNodeId, setRootNodeId] = useState<string | null>('1'); // Default to Jeffrey Epstein
  const [selectedEdgeTypes, setSelectedEdgeTypes] = useState<Set<string>>(
    new Set([
      'connection',
      'communication',
      'financial',
      'legal',
      'family',
      'business',
      'evidence',
      'co_occurrence',
      'co_mention',
    ]),
  );
  const [selectedNodeTypes, setSelectedNodeTypes] = useState<Set<string>>(
    new Set(['person', 'organization', 'location', 'event', 'document', 'evidence']),
  );
  const [hopsMap, setHopsMap] = useState<Map<string, number>>(new Map());

  // Initialize with optimized radial layout
  useEffect(() => {
    if (initialNodes.length === 0) return;

    // BFS is needed here for hops-based radial positioning
    const hopsMapForInit = new Map<string, number>();
    const rootId = rootNodeId || '1';

    // Simple local BFS just for init if global hopsMap isn't ready
    const queue: [string, number][] = [[rootId, 0]];
    hopsMapForInit.set(rootId, 0);

    const adj = new Map<string, string[]>();
    initialEdges.forEach((edge) => {
      if (!adj.has(edge.source)) adj.set(edge.source, []);
      if (!adj.has(edge.target)) adj.set(edge.target, []);
      adj.get(edge.source)!.push(edge.target);
      adj.get(edge.target)!.push(edge.source);
    });

    while (queue.length > 0) {
      const [currId, dist] = queue.shift()!;
      if (dist >= 5) continue;
      const neighbors = adj.get(currId) || [];
      for (const neighbor of neighbors) {
        if (!hopsMapForInit.has(neighbor)) {
          hopsMapForInit.set(neighbor, dist + 1);
          queue.push([neighbor, dist + 1]);
        }
      }
    }

    const spreadNodes = initialNodes.map((node) => {
      const hops = hopsMapForInit.get(node.id) ?? 3;
      const angle = Math.random() * 2 * Math.PI;
      const radius = hops === 0 ? 0 : 150 * hops + Math.random() * 50;

      return {
        ...node,
        position: node.position || {
          x: 400 + Math.cos(angle) * radius,
          y: 300 + Math.sin(angle) * radius,
        },
        color: node.color || getNodeColor(node.type, node.metadata?.riskLevel),
        size: node.size || getNodeSize(node.importance),
      };
    });

    setNodes(spreadNodes);
    setEdges(initialEdges);

    // Apply layout multiple times for better stabilization
    setTimeout(() => {
      applyForceLayout(spreadNodes, initialEdges, 200);
      setNodes([...spreadNodes]);
      centerNetwork();
    }, 100);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [initialNodes, initialEdges, rootNodeId]);

  // BFS calculation for hops from root
  useEffect(() => {
    if (!rootNodeId || nodes.length === 0) {
      setHopsMap(new Map());
      return;
    }

    const newHopsMap = new Map<string, number>();
    const queue: [string, number][] = [[rootNodeId, 0]];
    newHopsMap.set(rootNodeId, 0);

    // Build adjacency list for faster traversal
    const adj = new Map<string, string[]>();
    edges.forEach((edge) => {
      // Only traverse edges that meet the current strength and type requirements
      if (edge.strength < minStrength) return;
      if (!selectedEdgeTypes.has(edge.type)) return;

      if (!adj.has(edge.source)) adj.set(edge.source, []);
      if (!adj.has(edge.target)) adj.set(edge.target, []);
      adj.get(edge.source)!.push(edge.target);
      adj.get(edge.target)!.push(edge.source);
    });

    while (queue.length > 0) {
      const [currId, dist] = queue.shift()!;
      if (dist >= maxHops) continue;

      const neighbors = adj.get(currId) || [];
      for (const neighbor of neighbors) {
        if (!newHopsMap.has(neighbor)) {
          newHopsMap.set(neighbor, dist + 1);
          queue.push([neighbor, dist + 1]);
        }
      }
    }

    setHopsMap(newHopsMap);
  }, [nodes, edges, rootNodeId, maxHops, minStrength, selectedEdgeTypes]);

  // Apply filters
  useEffect(() => {
    let filtered = nodes;

    // Filter by node types
    filtered = filtered.filter((node) => selectedNodeTypes.has(node.type));

    // Filter by Hops from root
    if (rootNodeId && maxHops < 5) {
      // Only apply if we are not showing "all" (simulated by maxHops=5)
      filtered = filtered.filter((node) => hopsMap.has(node.id));
    }

    // Filter by Search
    if (searchTerm) {
      filtered = filtered.filter(
        (node) =>
          node.label.toLowerCase().includes(searchTerm.toLowerCase()) ||
          node.description?.toLowerCase().includes(searchTerm.toLowerCase()),
      );
    }

    setFilteredNodes(filtered);

    // Filter edges
    const filteredNodeIds = new Set(filtered.map((n) => n.id));
    setFilteredEdges(
      edges.filter((edge) => {
        const basics =
          filteredNodeIds.has(edge.source) &&
          filteredNodeIds.has(edge.target) &&
          edge.strength >= minStrength &&
          selectedEdgeTypes.has(edge.type);

        if (!basics) return false;
        if (damningEvidenceOnly) {
          return (edge.metadata.confidence || 0) > 0.8 && (edge.strength || 0) >= 7;
        }
        return true;
      }),
    );
  }, [
    nodes,
    edges,
    searchTerm,
    minStrength,
    selectedEdgeTypes,
    selectedNodeTypes,
    hopsMap,
    rootNodeId,
    maxHops,
    damningEvidenceOnly,
  ]);

  const getNodeColor = (type: string, riskLevel?: string): string => {
    const baseColors: Record<string, string> = {
      person: '#38bdf8', // Blue/Cyan
      organization: '#fbbf24', // Gold
      location: '#10b981', // green
      event: '#f472b6', // pink
      document: '#94a3b8', // slate
      evidence: '#f87171', // red
    };

    const riskColors: Record<string, string> = {
      low: '#22c55e',
      medium: '#eab308',
      high: '#f97316',
      critical: '#dc2626',
    };

    return riskLevel && riskLevel !== 'low'
      ? riskColors[riskLevel] || baseColors[type] || '#64748b'
      : baseColors[type] || '#64748b';
  };

  const getNodeSize = (importance: number): number => {
    return 8 + importance * 4; // 12-28px
  };

  const getEdgeColor = (type: string): string => {
    const colors: Record<string, string> = {
      connection: '#64748b',
      communication: '#3b82f6',
      financial: '#fbbf24',
      legal: '#ef4444',
      family: '#f472b6',
      business: '#38bdf8',
      evidence: '#f97316',
      co_occurrence: '#475569',
      co_mention: '#475569',
      Aviation: '#38bdf8',
      Banking: '#fbbf24',
      Investment: '#a855f7',
      Legal: '#ef4444',
      Personal: '#f472b6',
      Professional: '#3b82f6',
      'Real Estate': '#22c55e',
    };
    return colors[type] || '#64748b';
  };

  const applyForceLayout = (nodes: NetworkNode[], edges: NetworkEdge[], iterations = 150) => {
    const centerX = 400;
    const centerY = 300;
    const repulsionStrength = 2500;
    const attractionStrength = 0.05;

    // damping removed (unused)
    const radialForceStrength = 0.02;

    for (let i = 0; i < iterations; i++) {
      // 1. Repulsion between all nodes
      for (let j = 0; j < nodes.length; j++) {
        for (let k = j + 1; k < nodes.length; k++) {
          const nodeStepA = nodes[j];
          const nodeStepB = nodes[k];

          if (!nodeStepA.position || !nodeStepB.position) continue;

          const dx = nodeStepB.position.x - nodeStepA.position.x;
          const dy = nodeStepB.position.y - nodeStepA.position.y;
          const distance = Math.sqrt(dx * dx + dy * dy) || 1;

          if (distance < 500) {
            // Limit repulsion range for better performance
            const force = repulsionStrength / (distance * distance + 1);
            const fx = (dx / distance) * force;
            const fy = (dy / distance) * force;

            nodeStepA.position.x -= fx;
            nodeStepA.position.y -= fy;
            nodeStepB.position.x += fx;
            nodeStepB.position.y += fy;
          }
        }
      }

      // 2. Attraction for connected nodes (Clustering)
      edges.forEach((edge) => {
        const source = nodes.find((n) => n.id === edge.source);
        const target = nodes.find((n) => n.id === edge.target);

        if (!source?.position || !target?.position) return;

        const dx = target.position.x - source.position.x;
        const dy = target.position.y - source.position.y;
        const distance = Math.sqrt(dx * dx + dy * dy) || 1;

        // Increase attraction for higher strength connections
        const force = attractionStrength * Math.pow(distance, 1.2) * (edge.strength / 5);
        const fx = (dx / distance) * force;
        const fy = (dy / distance) * force;

        source.position.x += fx;
        source.position.y += fy;
        target.position.x -= fx;
        target.position.y -= fy;
      });

      // 3. Radial and Center Forces
      nodes.forEach((node) => {
        if (!node.position) return;

        const dx = node.position.x - centerX;
        const dy = node.position.y - centerY;
        const distance = Math.sqrt(dx * dx + dy * dy) || 1;

        // Radial constraint based on hops
        const hops = hopsMap.get(node.id) ?? 2;
        const targetRadius = hops === 0 ? 0 : 180 * hops;

        const radialDiff = distance - targetRadius;
        node.position.x -= (dx / distance) * radialDiff * radialForceStrength;
        node.position.y -= (dy / distance) * radialDiff * radialForceStrength;

        // Extra pull to center for high importance nodes
        if (node.importance > 3) {
          node.position.x -= dx * 0.01;
          node.position.y -= dy * 0.01;
        }
      });

      // 4. Damping / Area Bounds
      nodes.forEach((node) => {
        if (!node.position) return;

        // Keep within reasonable bounds
        const maxDist = 1200;
        const dx = node.position.x - centerX;
        const dy = node.position.y - centerY;
        const dist = Math.sqrt(dx * dx + dy * dy);

        if (dist > maxDist) {
          node.position.x = centerX + (dx / dist) * maxDist;
          node.position.y = centerY + (dy / dist) * maxDist;
        }
      });
    }
  };

  const drawNetwork = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Clear canvas
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // Apply zoom and pan
    ctx.save();
    ctx.translate(pan.x, pan.y);
    ctx.scale(zoom, zoom);

    // Draw edges
    filteredEdges.forEach((edge) => {
      const source = filteredNodes.find((n) => n.id === edge.source);
      const target = filteredNodes.find((n) => n.id === edge.target);

      if (!source?.position || !target?.position) return;

      const edgeColor = getEdgeColor(edge.type);
      ctx.beginPath();
      ctx.moveTo(source.position.x, source.position.y);
      ctx.lineTo(target.position.x, target.position.y);

      ctx.strokeStyle = edgeColor;
      ctx.lineWidth = edge.strength * 0.5; // Fine lines
      ctx.globalAlpha = 0.25; // Translucent lines

      if (edge.metadata.was_agentic) {
        ctx.setLineDash([2, 4]); // Dotted for agentic
      } else if (edge.direction === 'bidirectional') {
        ctx.setLineDash([]); // Solid for verified/regular
      } else {
        ctx.setLineDash([8, 4]); // Dashed for directional/inferred
      }

      ctx.stroke();
      ctx.setLineDash([]);
      ctx.globalAlpha = 1;
    });

    // Draw nodes
    filteredNodes.forEach((node) => {
      if (!node.position) return;

      const isSelected = node.id === selectedNodeId;
      const isRoot = node.id === rootNodeId;
      const nodeSize = node.size || 12;

      // Glow Effect
      ctx.shadowBlur = isSelected ? 20 : 15;
      ctx.shadowColor = node.color || '#3b82f6';

      // Root Halo
      if (isRoot) {
        ctx.beginPath();
        ctx.arc(node.position.x, node.position.y, nodeSize + 8, 0, 2 * Math.PI);
        ctx.strokeStyle = node.color || '#3b82f6';
        ctx.lineWidth = 2;
        ctx.globalAlpha = 0.3;
        ctx.stroke();
        ctx.globalAlpha = 1;
      }

      // Draw node circle
      ctx.beginPath();
      ctx.arc(node.position.x, node.position.y, nodeSize, 0, 2 * Math.PI);

      ctx.fillStyle = node.color || '#3b82f6';
      ctx.fill();

      // Reset shadows for details
      ctx.shadowBlur = 0;

      if (isSelected) {
        ctx.strokeStyle = '#ffffff';
        ctx.lineWidth = 3;
        ctx.stroke();
      }

      // Draw node icon
      ctx.fillStyle = '#ffffff';
      ctx.font = 'bold 12px sans-serif';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';

      const icon = getNodeIcon(node.type);
      ctx.fillText(icon, node.position.x, node.position.y);

      // Draw node label (only for important nodes or if zoomed in enough)
      const shouldDrawLabel = zoom > 0.6 || node.importance > 3 || isSelected;
      if (shouldDrawLabel) {
        ctx.fillStyle = 'rgba(255, 255, 255, 0.9)';
        ctx.font = node.importance > 4 ? 'bold 13px Inter, sans-serif' : '11px Inter, sans-serif';
        ctx.textAlign = 'center';
        ctx.fillText(node.label, node.position.x, node.position.y + nodeSize + 18);
      }

      // Draw importance indicator
      if (node.importance > 3) {
        ctx.beginPath();
        ctx.arc(node.position.x + nodeSize - 2, node.position.y - nodeSize + 2, 4, 0, 2 * Math.PI);
        ctx.fillStyle = '#fbbf24';
        ctx.fill();
        ctx.strokeStyle = '#000000';
        ctx.lineWidth = 1;
        ctx.stroke();
      }
    });

    ctx.restore();
  };

  const getNodeIcon = (type: NetworkNode['type']): string => {
    const icons = {
      person: '👤',
      document: '📄',
      organization: '🏢',
      location: '📍',
      event: '📅',
      evidence: '🔍',
    };
    return icons[type];
  };

  useEffect(() => {
    drawNetwork();
    // eslint-disable-next-line react-hooks/exhaustive-deps -- drawNetwork is stable and depends on filtered data
  }, [filteredNodes, filteredEdges, selectedNodeId, selectedEdgeId, zoom, pan]);

  const handleCanvasClick = (event: React.MouseEvent<HTMLCanvasElement>) => {
    if (!interactive) return;

    const canvas = canvasRef.current;
    if (!canvas) return;

    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;

    const x = ((event.clientX - rect.left) * scaleX - pan.x) / zoom;
    const y = ((event.clientY - rect.top) * scaleY - pan.y) / zoom;

    // Check if click is on a node
    const clickedNode = filteredNodes.find((node) => {
      if (!node.position) return false;
      const distance = Math.sqrt(
        Math.pow(x - node.position.x, 2) + Math.pow(y - node.position.y, 2),
      );
      return distance <= (node.size || 12);
    });

    if (clickedNode) {
      onNodeClick?.(clickedNode);
      return;
    }

    // Check if click is on an edge
    const clickedEdge = filteredEdges.find((edge) => {
      const source = filteredNodes.find((n) => n.id === edge.source);
      const target = filteredNodes.find((n) => n.id === edge.target);

      if (!source?.position || !target?.position) return false;

      // Distance from point to line segment
      const A = x - source.position.x;
      const B = y - source.position.y;
      const C = target.position.x - source.position.x;
      const D = target.position.y - source.position.y;

      const dot = A * C + B * D;
      const len_sq = C * C + D * D;
      let param = -1;
      if (len_sq !== 0)
        // in case of 0 length line
        param = dot / len_sq;

      let xx, yy;

      if (param < 0) {
        xx = source.position.x;
        yy = source.position.y;
      } else if (param > 1) {
        xx = target.position.x;
        yy = target.position.y;
      } else {
        xx = source.position.x + param * C;
        yy = source.position.y + param * D;
      }

      const dx = x - xx;
      const dy = y - yy;
      const distance = Math.sqrt(dx * dx + dy * dy);

      return distance < 5; // 5px tolerance
    });

    if (clickedEdge) {
      onEdgeClick?.(clickedEdge);
    }
  };

  // Enhanced zoom to center on mouse position
  const handleWheelEnhanced = (event: React.WheelEvent<HTMLCanvasElement>) => {
    if (!interactive) return;

    event.preventDefault();
    const delta = event.deltaY > 0 ? 0.9 : 1.1;

    // Get mouse position relative to canvas
    const canvas = canvasRef.current;
    if (!canvas) return;

    const rect = canvas.getBoundingClientRect();
    const mouseX = event.clientX - rect.left;
    const mouseY = event.clientY - rect.top;

    // Scale for internal resolution
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;

    // Convert screen coordinates to world coordinates
    const worldMouseX = (mouseX * scaleX - pan.x) / zoom;
    const worldMouseY = (mouseY * scaleY - pan.y) / zoom;

    // Apply zoom
    const newZoom = Math.max(0.1, Math.min(3, zoom * delta));

    // Adjust pan to keep mouse position fixed
    const newPanX = mouseX * scaleX - worldMouseX * newZoom;
    const newPanY = mouseY * scaleY - worldMouseY * newZoom;

    setZoom(newZoom);
    setPan({ x: newPanX, y: newPanY });
  };

  const centerNetwork = () => {
    if (filteredNodes.length === 0) return;

    const canvas = canvasRef.current;
    if (!canvas) return;

    // Calculate center of all nodes
    const bounds = filteredNodes.reduce(
      (acc, node) => {
        if (!node.position) return acc;
        return {
          minX: Math.min(acc.minX, node.position.x),
          maxX: Math.max(acc.maxX, node.position.x),
          minY: Math.min(acc.minY, node.position.y),
          maxY: Math.max(acc.maxY, node.position.y),
        };
      },
      { minX: Infinity, maxX: -Infinity, minY: Infinity, maxY: -Infinity },
    );

    const centerX = (bounds.minX + bounds.maxX) / 2;
    const centerY = (bounds.minY + bounds.maxY) / 2;

    // Center the network on canvas
    const canvasCenterX = canvas.width / 2;
    const canvasCenterY = canvas.height / 2;

    setPan({
      x: canvasCenterX - centerX * zoom,
      y: canvasCenterY - centerY * zoom,
    });
  };

  const handleMouseDown = (event: React.MouseEvent<HTMLCanvasElement>) => {
    if (!interactive) return;

    setIsDragging(true);
    setDragStart({ x: event.clientX, y: event.clientY });
    setLastPan({ x: pan.x, y: pan.y });
  };

  const handleMouseMove = (event: React.MouseEvent<HTMLCanvasElement>) => {
    if (!interactive || !isDragging) return;

    const rect = (event.target as HTMLCanvasElement).getBoundingClientRect();
    const scaleX = (event.target as HTMLCanvasElement).width / rect.width;
    const scaleY = (event.target as HTMLCanvasElement).height / rect.height;

    const deltaX = (event.clientX - dragStart.x) * scaleX;
    const deltaY = (event.clientY - dragStart.y) * scaleY;

    setPan({
      x: lastPan.x + deltaX,
      y: lastPan.y + deltaY,
    });
  };

  const handleMouseUp = () => {
    setIsDragging(false);
  };

  const exportNetwork = () => {
    const data = {
      nodes: filteredNodes,
      edges: filteredEdges,
      exportDate: new Date().toISOString(),
      totalNodes: nodes.length,
      totalEdges: edges.length,
    };

    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `network-analysis-${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const Checkbox = ({
    label,
    checked,
    onChange,
    color,
  }: {
    label: string;
    checked: boolean;
    onChange: (checked: boolean) => void;
    color?: string;
  }) => (
    <div
      className="flex items-center gap-3 py-1 cursor-pointer group"
      onClick={() => onChange(!checked)}
    >
      <div
        className={`w-5 h-5 rounded border flex items-center justify-center transition-all ${checked ? 'bg-blue-600 border-blue-500' : 'bg-slate-800 border-slate-600 group-hover:border-slate-500'}`}
      >
        {checked && <Zap className="w-3 h-3 text-white fill-current" />}
      </div>
      <div className="flex items-center gap-2">
        {color && <div className="w-2 h-2 rounded-full" style={{ backgroundColor: color }} />}
        <span className={`text-sm font-medium ${checked ? 'text-slate-100' : 'text-slate-400'}`}>
          {label}
        </span>
      </div>
    </div>
  );

  return (
    <div className="bg-slate-900 rounded-xl border border-slate-700/50 overflow-hidden shadow-2xl flex flex-col h-full min-h-[600px]">
      {/* Header */}
      <div className="p-4 border-b border-slate-700/50 bg-slate-900/80 backdrop-blur-md z-10">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="bg-blue-500/10 p-2 rounded-lg">
              <Network className="w-5 h-5 text-blue-400" />
            </div>
            <div>
              <h3 className="text-lg font-bold text-white tracking-tight">
                Epstein Network Analysis
              </h3>
              <div className="flex items-center gap-2 text-xs text-slate-400">
                <span className="flex items-center gap-1">
                  <Users className="w-3 h-3" /> {nodes.length} entities
                </span>
                <span>•</span>
                <span className="flex items-center gap-1">
                  <Zap className="w-3 h-3" /> {edges.length} connections
                </span>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <div className="relative mr-4 hidden md:block">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-slate-400" />
              <input
                type="text"
                placeholder="Search entities..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="h-10 pl-10 pr-4 bg-slate-800/50 border border-slate-700 rounded-lg text-white text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all w-64"
              />
            </div>

            <button
              onClick={() => setShowTableView(!showTableView)}
              className={`h-10 px-4 flex items-center gap-2 rounded-lg text-sm font-semibold transition-all ${
                showTableView
                  ? 'bg-blue-600 text-white shadow-lg shadow-blue-500/20'
                  : 'bg-slate-800 text-slate-300 hover:bg-slate-700 border border-slate-700'
              }`}
            >
              {showTableView ? <Network className="w-4 h-4" /> : <FileText className="w-4 h-4" />}
              <span>{showTableView ? 'Visual Graph' : 'Data Table'}</span>
            </button>

            <button
              onClick={() => setShowSettings(!showSettings)}
              className={`h-10 w-10 flex items-center justify-center rounded-lg transition-all ${showSettings ? 'bg-slate-700 text-white' : 'bg-slate-800 text-slate-400 border border-slate-700'}`}
            >
              <Settings className="w-4 h-4" />
            </button>

            <button
              onClick={exportNetwork}
              className="h-10 w-10 flex items-center justify-center bg-slate-800 border border-slate-700 rounded-lg text-slate-400 hover:text-white transition-all"
              title="Export Network"
            >
              <Download className="w-4 h-4" />
            </button>
          </div>
        </div>
      </div>

