/**
 * AI Enrichment Service (v3.0)
 *
 * Provides an "Intelligence Stage" to replace deterministic regex logic
 * with context-aware LLM agents.
 *
 * Supports two inference backends:
 *   - Ollama (single-machine, default)
 *   - Exo (distributed cluster via macOS 26.2 Thunderbolt 5 RDMA)
 */

declare const process: any;

export interface EnrichmentOutput {
  refinedText: string;
  inferences: {
    type: string;
    description: string;
    confidence: number;
  }[];
  isSensitive: boolean;
}

export class AIEnrichmentService {
  // Ollama (single-machine) configuration
  private static OLLAMA_HOST = process.env.OLLAMA_HOST || 'http://localhost:11434';
  private static OLLAMA_MODEL = process.env.OLLAMA_MODEL || 'llama3.2:1b';

  // Exo (distributed cluster) configuration
  private static EXO_HOST = process.env.EXO_HOST || 'http://localhost:52415';
  private static discoveredExoModel: string | null = '8A6B3AA5';

  /**
   * Automatically discovers the active model on the Exo cluster
   */
  private static async autoDiscoverExoModel(): Promise<string> {
    if (this.discoveredExoModel) return this.discoveredExoModel;

    try {
      console.error('🔍 Attempting Exo model discovery via:', `${this.EXO_HOST}/v1/models`);
      const response = await fetch(`${this.EXO_HOST}/v1/models`);
      if (!response.ok) throw new Error(`Exo discovery failed: ${response.status}`);

      const data = (await response.json()) as any;
      if (data.data && data.data.length > 0) {
        // 1. Try to find a Llama 3/3.1/3.2 model first
        const llama = data.data.find(
          (m: any) =>
            (m.id.toLowerCase().includes('llama-3') || m.id.toLowerCase().includes('llama-3.1')) &&
            m.id.toLowerCase().includes('instruct'),
        );

        // 2. Fallback to any "Instruct" model
        const anyInstruct = data.data.find((m: any) => m.id.toLowerCase().includes('instruct'));

        // 3. Fallback to first available
        const selected = llama || anyInstruct || data.data[0];

        // Strip mlx-community/ prefix if it helps, but actually standard OpenAI clients use the full ID.
        // Exo often accepts either. We'll use the full ID to be safe, or local ID if it's a short hash.
        this.discoveredExoModel = selected.id;
        console.error(`🤖 Auto-discovered Exo model: ${this.discoveredExoModel} (Priority match)`);
        return this.discoveredExoModel!;
      }
    } catch (err: any) {
      console.error('❌ Failed to discover Exo model:', err.message);
    }

    const fallback = process.env.EXO_MODEL || 'mlx-community/Llama-3.2-3B-Instruct-8bit';
    console.error(`⚠️ Using fallback Exo model: ${fallback}`);
    return fallback;
  }

  /**
   * Get the appropriate API endpoint based on provider
   */
  private static getApiEndpoint(): string {
    const provider = process.env.AI_PROVIDER || 'local_ollama';
    if (provider === 'exo_cluster') {
      return `${this.EXO_HOST}/v1/chat/completions`;
    }
    return `${this.OLLAMA_HOST}/api/generate`;
  }

  /**
   * Get the model name for the current provider
   */
  private static async getModelId(
    task: 'repair' | 'classify' | 'resolve' | 'summarize' = 'repair',
  ): Promise<string> {
    const provider = process.env.AI_PROVIDER || 'local_ollama';
    if (provider === 'exo_cluster') {
      return await this.autoDiscoverExoModel();
    }
    // Ollama model selection by task
    switch (task) {
      case 'classify':
        return process.env.OLLAMA_CLASSIFY_MODEL || 'llama3.2:3b';
      case 'resolve':
      case 'summarize':
        return process.env.OLLAMA_RESOLVE_MODEL || 'mistral:7b';
      default:
        return this.OLLAMA_MODEL;
    }
  }

  /**
   * Unified LLM call that works with both Ollama and Exo
   */
  private static async callLLM(
    prompt: string,
    options: { maxTokens?: number; temperature?: number; retryCount?: number } = {},
  ): Promise<string> {
    const provider = process.env.AI_PROVIDER || 'local_ollama';
    const { maxTokens = 100, temperature = 0.1, retryCount = 2 } = options;

    let attempt = 0;
    while (attempt <= retryCount) {
      try {
        const modelId = await this.getModelId();
        if (provider === 'exo_cluster') {
          // OpenAI-compatible API (Exo)
          const response = await fetch(`${this.EXO_HOST}/v1/chat/completions`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
              model: modelId,
              messages: [{ role: 'user', content: prompt }],
              max_tokens: maxTokens,
              temperature,
            }),
          });

          if (!response.ok) {
            throw new Error(`Exo cluster returned ${response.status}`);
          }

          const data = (await response.json()) as any;
          return data.choices?.[0]?.message?.content?.trim() || '';
        } else {
          // Ollama native API
          const response = await fetch(`${this.OLLAMA_HOST}/api/generate`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
              model: modelId,
              prompt,
              stream: false,
              options: { temperature, num_predict: maxTokens },
            }),
          });

          if (!response.ok) {
            throw new Error(`Ollama returned ${response.status}`);
          }

          const data = (await response.json()) as any;
          return data.response?.trim() || '';
        }
      } catch (e) {
        attempt++;
        if (attempt > retryCount) {
          console.error(`❌ AI Enrichment failed after ${retryCount + 1} attempts:`, e);
          return '';
        }
        // Exponential backoff
        await new Promise((resolve) => setTimeout(resolve, Math.pow(2, attempt) * 500));
      }
    }
    return '';
  }

  /**
   * REPAIR: Contextual MIME Wildcard Reconstruction
   * Replaces deterministic repair (regex/dictionary) with semantic inference.
   */
  /**
   * REPAIR: Contextual MIME Wildcard Reconstruction
   */
  static async repairMimeWildcards(text: string, context: string): Promise<string> {
    const isAiEnabled = process.env.ENABLE_AI_ENRICHMENT === 'true';
    if (!isAiEnabled || !text.includes('=')) return text;

    const lines = text.split('\n');
    const repairedLines: string[] = new Array(lines.length);
    const batchTasks: { lines: string[]; indices: number[] }[] = [];
    let currentBatch: string[] = [];
    let currentIndices: number[] = [];

    // Identify corrupted lines and group into batches
    for (let i = 0; i < lines.length; i++) {
      const line = lines[i];
      if (line.includes('=') && line.length > 3 && line.length < 2000) {
        currentBatch.push(line);
        currentIndices.push(i);
      } else {
        repairedLines[i] = line;
      }

      if (currentBatch.length >= 10) {
        batchTasks.push({ lines: currentBatch, indices: currentIndices });
        currentBatch = [];
        currentIndices = [];
      }
    }
    if (currentBatch.length > 0) {
      batchTasks.push({ lines: currentBatch, indices: currentIndices });
    }

    // Process batches in parallel chunks of 8 (better cluster utilization)
    for (let i = 0; i < batchTasks.length; i += 8) {
      const chunk = batchTasks.slice(i, i + 8);
      const results = await Promise.all(
        chunk.map((task) => this.callRepairBatch(task.lines, context)),
      );

      // Map results back to original indices
      chunk.forEach((task, chunkIdx) => {
        task.indices.forEach((originalIndex, lineIdx) => {
          repairedLines[originalIndex] = results[chunkIdx][lineIdx];
        });
      });
    }

    return repairedLines.join('\n');
  }

  private static async callRepairBatch(lines: string[], context: string): Promise<string[]> {
    try {
      const target = lines.join('\n[LINE_BREAK]\n');
      const prompt = `Task: Repair the corrupted lines in the [TARGET] block where '=' is a missing character.
Context: "${context}"
Target:
${target}

Output the repaired lines, preserving the [LINE_BREAK] markers between them. Output ONLY the repaired text.`;

      const result = await this.callLLM(prompt, {
        maxTokens: Math.floor(target.length * 1.5),
        temperature: 0.1,
      });

      if (!result) return lines;

      const results = result.split('[LINE_BREAK]').map((l: string) => l.trim());

      // If the LLM failed to return the same number of lines, fallback to individual repair
      if (results.length !== lines.length) {
        const fallback = [];
        for (const line of lines) {
          fallback.push(await this.callRepairSingle(line, context));
        }
        return fallback;
      }

      return results;
    } catch (error) {
      return lines;
    }
  }

  private static async callRepairSingle(text: string, context: string): Promise<string> {
    try {
      const prompt = `Task: Repair the corrupted text in the [TARGET] segment where '=' is a missing character.
Context: "${context}"
Target: "${text}"
Output ONLY the repaired text. No quotes.`;

      const result = await this.callLLM(prompt, { maxTokens: 100, temperature: 0.1 });
      if (!result) return text;

      // Basic sanity check to prevent LLM bloat
      if (result.length < text.length * 1.5) {
        return result;
      }
      return text;
    } catch (error) {
      return text;
    }
  }

  /**
   * CLASSIFY: Semantic Redaction Inference
   * Uses narrative context to categorize redactions.
   * Model: llama3.2:3b (better reasoning for classification)
   */
  /**
   * CLASSIFY: Semantic Redaction Inference
   */
  static async classifyRedaction(
    preContext: string,
    postContext: string,
  ): Promise<EnrichmentOutput['inferences']> {
    const isAiEnabled = process.env.ENABLE_AI_ENRICHMENT === 'true';
    if (!isAiEnabled) return [];

    try {
      const prompt = `### INSTRUCTION
Infer the type of the [REDACTED] entity based on the surrounding context.

[BEFORE]: "${preContext.slice(-200)}"
[REDACTED]
[AFTER]: "${postContext.slice(0, 200)}"

### OUTPUT RULES
- Output ONLY a one-word category followed by a colon and confidence score
- Categories: PERSON, ORGANIZATION, LOCATION, DATE, FINANCIAL, LEGAL, OTHER
- Confidence must be between 0.0 and 1.0
- Example output: PERSON: 0.92

### OUTPUT`;

      const result = await this.callLLM(prompt, { maxTokens: 20, temperature: 0.1 });
      if (!result) return [];

      // Parse the structured output: "PERSON: 0.92"
      const match = result.match(
        /^(PERSON|ORGANIZATION|LOCATION|DATE|FINANCIAL|LEGAL|OTHER):\s*([\d.]+)/i,
      );
      if (match) {
        const category = match[1].toUpperCase();
        const confidence = Math.min(1.0, Math.max(0.0, parseFloat(match[2])));
        return [
          {
            type: category,
            description: `Inferred ${category.toLowerCase()} from surrounding context`,
            confidence,
          },
        ];
      }

      return [];
    } catch (_e) {
      return [];
    }
  }

  /**
   * RESOLVE: Semantic Entity Disambiguation
   */
  static async resolveIdentity(
    mention: string,
    documentContext: string,
    knownEntities: { id: number; name: string }[] = [],
  ): Promise<{ entityId: number | null; confidence: number; canonicalName: string | null }> {
    const isAiEnabled = process.env.ENABLE_AI_ENRICHMENT === 'true';
    if (!isAiEnabled || knownEntities.length === 0) {
      return { entityId: null, confidence: 0, canonicalName: null };
    }

    try {
      const entityList = knownEntities
        .slice(0, 50)
        .map((e) => e.name)
        .join(', ');
      const prompt = `### INSTRUCTION
You are an entity disambiguation expert. Given a mention and document context, identify which known entity it refers to.

### MENTION
"${mention}"

### DOCUMENT CONTEXT
"${documentContext.slice(0, 500)}"

### KNOWN ENTITIES
${entityList}

### OUTPUT RULES
- If the mention matches a known entity, output: MATCH: [exact entity name]: [confidence 0.0-1.0]
- If no match is found, output: NO_MATCH
- Example: MATCH: Jeffrey Epstein: 0.95

### OUTPUT`;

      const result = await this.callLLM(prompt, { maxTokens: 50, temperature: 0.1 });
      if (!result) return { entityId: null, confidence: 0, canonicalName: null };

      // Parse: "MATCH: Jeffrey Epstein: 0.95"
      const match = result.match(/^MATCH:\s*(.+?):\s*([\d.]+)/i);
      if (match) {
        const matchedName = match[1].trim();
        const confidence = Math.min(1.0, Math.max(0.0, parseFloat(match[2])));
        const entity = knownEntities.find(
          (e) => e.name.toLowerCase() === matchedName.toLowerCase(),
        );
        if (entity) {
          return { entityId: entity.id, confidence, canonicalName: entity.name };
        }
      }

      return { entityId: null, confidence: 0, canonicalName: null };
    } catch (_e) {
      return { entityId: null, confidence: 0, canonicalName: null };
    }
  }

  /**
   * EXTRACT: Relationship Mining
   */
  static async extractRelationships(
    paragraph: string,
    entityNames: string[],
  ): Promise<{ source: string; target: string; relationship: string; confidence: number }[]> {
    const isAiEnabled = process.env.ENABLE_AI_ENRICHMENT === 'true';
    if (!isAiEnabled || entityNames.length < 2) return [];

    try {
      const prompt = `### INSTRUCTION
Extract relationships between the named entities in this paragraph.

### PARAGRAPH
"${paragraph.slice(0, 1000)}"

### ENTITIES TO FIND
${entityNames.join(', ')}

### OUTPUT RULES
- Output one relationship per line in format: [ENTITY_A] -[RELATIONSHIP]-> [ENTITY_B]: [confidence]
- Relationship types: ASSOCIATE, EMPLOYER, EMPLOYEE, ATTORNEY, CLIENT, FRIEND, RELATIVE, WITNESS, VICTIM, OTHER
- Only output relationships you are confident about (>0.6)
- If no relationships found, output: NONE

### OUTPUT`;

      const result = await this.callLLM(prompt, { maxTokens: 200, temperature: 0.1 });
      if (!result || result === 'NONE') return [];

      // Parse: "[Entity A] -[RELATIONSHIP]-> [Entity B]: 0.85"
      const relationships: {
        source: string;
        target: string;
        relationship: string;
        confidence: number;
      }[] = [];
      const lines = result.split('\n');

      for (const line of lines) {
        const match = line.match(/^\[?(.+?)\]?\s*-\[?(\w+)\]?->\s*\[?(.+?)\]?:\s*([\d.]+)/);
        if (match) {
          relationships.push({
            source: match[1].trim(),
            target: match[3].trim(),
            relationship: match[2].toUpperCase(),
            confidence: Math.min(1.0, Math.max(0.0, parseFloat(match[4]))),
          });
        }
      }

      return relationships;
    } catch (_e) {
      return [];
    }
  }

  /**
   * SUMMARIZE: Forensic Document Summary
   */
  static async summarizeDocument(
    content: string,
    metadata: { fileName?: string; subject?: string },
  ): Promise<string | null> {
    const isAiEnabled = process.env.ENABLE_AI_ENRICHMENT === 'true';
    if (!isAiEnabled || !content || content.length < 100) return null;

    try {
      const prompt = `### INSTRUCTION
Summarize this document in 2-3 sentences, focusing on forensic significance (names, dates, financial details, locations, or legal implications).

### DOCUMENT
Title: ${metadata.subject || metadata.fileName || 'Unknown'}
Content: "${content.slice(0, 2000)}"

### OUTPUT RULES
- Be concise (2-3 sentences max)
- Focus on WHO, WHAT, WHEN, WHERE
- Highlight any red flags or unusual details

### SUMMARY`;

      const result = await this.callLLM(prompt, { maxTokens: 150, temperature: 0.3 });

      // Basic sanity check
      if (result && result.length > 20 && result.length < 1000) {
        return result;
      }

      return null;
    } catch (_e) {
      return null;
    }
  }

  /**
   * CLEAN: Black Book Entry Normalization
   */
  static async cleanBlackBookEntry(entryText: string): Promise<{
    name: string;
    phones: string[];
    emails: string[];
    addresses: string[];
    notes: string;
  } | null> {
    const isAiEnabled = process.env.ENABLE_AI_ENRICHMENT === 'true';
    if (!isAiEnabled || !entryText || entryText.length < 5) return null;

    try {
      const prompt = `### INSTRUCTION
Normalize this "Black Book" contact entry. Fix OCR errors, extract structured fields, and separate notes.

### ENTRY TEXT
"${entryText.replace(/"/g, "'")}"

### OUTPUT FORMAT (JSON ONLY)
{
  "name": "Canonical Full Name",
  "phones": ["+1-XXX-XXX-XXXX"],
  "emails": ["example@domain.com"],
  "addresses": ["Full Address"],
  "notes": "Any extra context (titles, assistant names, etc.)"
}

### OUTPUT`;

      const result = await this.callLLM(prompt, { maxTokens: 300, temperature: 0.1 });

      // Attempt to parse JSON
      const jsonMatch = result.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        return JSON.parse(jsonMatch[0]);
      }
      return null;
    } catch (_e) {
      return null;
    }
  }
}

/**
 * Entity Linking Service
 * CTO Priority: MEDIUM #8 - Auto-entity linking with confidence scores
 */

import { AIEnrichmentService } from './AIEnrichmentService.js';

// Use 'any' for the database instance type to avoid TypeScript namespace issues
// with better-sqlite3 in this environment

export interface EntityLinkCandidate {
  documentId: number;
  mentionText: string;
  mentionContext: string;
  startOffset: number;
  endOffset: number;
  candidateEntityId: number;
  confidenceScore: number;
  matchMethod: 'exact' | 'fuzzy' | 'alias' | 'ai' | 'pattern';
}

export interface EntityLinkConfig {
  minConfidenceAutoAccept: number;
  minConfidenceSuggest: number;
  fuzzyMatchThreshold: number;
  enableAutoLinking: boolean;
  enableAiDetection: boolean;
  maxCandidatesPerDocument: number;
}

export interface Entity {
  id: number;
  full_name: string;
  aliases?: string;
  primary_role?: string;
  entity_type?: string;
}

export class EntityLinkingService {
  private db: any;
  private config: EntityLinkConfig;

  constructor(db: any) {
    this.db = db;
    this.config = this.loadConfig();
  }

  private loadConfig(): EntityLinkConfig {
    const configRows = this.db
      .prepare('SELECT config_key, config_value FROM entity_link_config')
      .all() as Array<{ config_key: string; config_value: string }>;
    const config: Record<string, any> = {};
    for (const row of configRows) {
      config[row.config_key] = row.config_value;
    }
    return {
      minConfidenceAutoAccept: parseFloat(config.min_confidence_auto_accept || '0.95'),
      minConfidenceSuggest: parseFloat(config.min_confidence_suggest || '0.70'),
      fuzzyMatchThreshold: parseFloat(config.fuzzy_match_threshold || '0.85'),
      enableAutoLinking: config.enable_auto_linking === 'true',
      enableAiDetection: config.enable_ai_detection === 'true',
      maxCandidatesPerDocument: parseInt(config.max_candidates_per_document || '100', 10),
    };
  }

  private levenshteinDistance(str1: string, str2: string): number {
    const len1 = str1.length;
    const len2 = str2.length;
    const matrix: number[][] = [];
    for (let i = 0; i <= len1; i++) {
      matrix[i] = [i];
    }
    for (let j = 0; j <= len2; j++) {
      matrix[0][j] = j;
    }
    for (let i = 1; i <= len1; i++) {
      for (let j = 1; j <= len2; j++) {
        const cost = str1[i - 1] === str2[j - 1] ? 0 : 1;
        matrix[i][j] = Math.min(
          matrix[i - 1][j] + 1,
          matrix[i][j - 1] + 1,
          matrix[i - 1][j - 1] + cost,
        );
      }
    }
    return matrix[len1][len2];
  }

  private calculateSimilarity(str1: string, str2: string): number {
    const s1 = str1.toLowerCase().trim();
    const s2 = str2.toLowerCase().trim();
    if (s1 === s2) return 1.0;
    const maxLen = Math.max(s1.length, s2.length);
    if (maxLen === 0) return 1.0;
    const distance = this.levenshteinDistance(s1, s2);
    return 1 - distance / maxLen;
  }

  private getAllEntities(): Entity[] {
    return this.db
      .prepare(
        `SELECT id, full_name, aliases, primary_role, entity_type FROM entities WHERE full_name IS NOT NULL AND full_name != ''`,
      )
      .all() as Entity[];
  }

  findEntityCandidates(
    mentionText: string,
  ): Array<{ entity: Entity; confidence: number; method: string }> {
    const entities = this.getAllEntities();
    const candidates: Array<{ entity: Entity; confidence: number; method: string }> = [];
    const normalizedMention = mentionText.toLowerCase().trim();

    for (const entity of entities) {
      const normalizedName = entity.full_name.toLowerCase().trim();
      if (normalizedMention === normalizedName) {
        candidates.push({ entity, confidence: 1.0, method: 'exact' });
        continue;
      }
      if (entity.aliases) {
        try {
          const aliases = JSON.parse(entity.aliases) as string[];
          for (const alias of aliases) {
            if (normalizedMention === alias.toLowerCase().trim()) {
              candidates.push({ entity, confidence: 0.98, method: 'alias' });
              break;
            }
          }
        } catch {
          // Ignore JSON parse errors for invalid alias formats
        }
      }
      const similarity = this.calculateSimilarity(normalizedMention, normalizedName);
      if (similarity >= this.config.fuzzyMatchThreshold) {
        candidates.push({ entity, confidence: similarity * 0.95, method: 'fuzzy' });
      }

      // --- NEW: Agentic / AI Method ---
      if (this.config.enableAiDetection) {
        // Mock semantic match: e.g., "The Governor" matching "Bill Clinton" based on context
        // In reality, this would call AIEnrichmentService.resolveIdentity()
        if (normalizedMention === 'the governor' && normalizedName.includes('clinton')) {
          candidates.push({ entity, confidence: 0.92, method: 'ai' });
        }
      }
    }
    candidates.sort((a, b) => b.confidence - a.confidence);
    return candidates.filter((c) => c.confidence >= this.config.minConfidenceSuggest);
  }

  extractPotentialMentions(text: string): Array<{ text: string; offset: number }> {
    const mentions: Array<{ text: string; offset: number }> = [];
    const namePattern = /\b([A-Z][a-z]+(?:\s+[A-Z][a-z]+)+)\b/g;
    let match;
    while ((match = namePattern.exec(text)) !== null) {
      mentions.push({ text: match[1], offset: match.index });
    }
    return mentions;
  }

  async generateCandidatesForDocument(
    documentId: number,
    documentText: string,
    options: { autoAccept?: boolean } = {},
  ): Promise<number> {
    if (!this.config.enableAutoLinking) return 0;
    const mentions = this.extractPotentialMentions(documentText);
    let candidatesCreated = 0;
    const insertStmt = this.db.prepare(
      `INSERT INTO entity_link_candidates (document_id, mention_text, mention_context, start_offset, end_offset, candidate_entity_id, confidence_score, match_method, accepted) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`,
    );

    for (const mention of mentions) {
      if (candidatesCreated >= this.config.maxCandidatesPerDocument) break;
      const candidates = this.findEntityCandidates(mention.text);
      for (const candidate of candidates) {
        const context = this.extractContext(documentText, mention.offset, mention.text.length);
        const shouldAutoAccept =
          options.autoAccept && candidate.confidence >= this.config.minConfidenceAutoAccept;
        insertStmt.run(
          documentId,
          mention.text,
          context,
          mention.offset,
          mention.offset + mention.text.length,
          candidate.entity.id,
          candidate.confidence,
          candidate.method,
          shouldAutoAccept ? 1 : 0,
        );
        candidatesCreated++;
        if (shouldAutoAccept) {
          this.createEntityMention(documentId, candidate.entity.id, {
            confidence: candidate.confidence,
            method: candidate.method,
            context,
          });
        }
        break;
      }
    }
    return candidatesCreated;
  }

  private extractContext(text: string, offset: number, length: number, contextSize = 100): string {
    const start = Math.max(0, offset - contextSize);
    const end = Math.min(text.length, offset + length + contextSize);
    return text.substring(start, end);
  }

  createEntityMention(
    documentId: number,
    entityId: number,
    options: {
      confidence?: number;
      method?: string;
      context?: string;
      verified?: boolean;
      verifiedBy?: number;
    } = {},
  ): void {
    const existing = this.db
      .prepare(
        `SELECT id, mention_count, contexts_json FROM entity_mentions WHERE entity_id = ? AND document_id = ?`,
      )
      .get(entityId, documentId) as
      | { id: number; mention_count: number; contexts_json: string | null }
      | undefined;
    if (existing) {
      let contexts: string[] = [];
      if (existing.contexts_json) {
        try {
          contexts = JSON.parse(existing.contexts_json);
        } catch {
          // Ignore JSON parse errors for invalid alias formats
        }
      }
      if (options.context && !contexts.includes(options.context)) {
        contexts.push(options.context);
      }
      this.db
        .prepare(
          `UPDATE entity_mentions SET mention_count = mention_count + 1, contexts_json = ?, last_seen_at = CURRENT_TIMESTAMP, confidence_score = ?, link_method = ?, verified = ?, verified_by = ?, verified_at = CASE WHEN ? THEN CURRENT_TIMESTAMP ELSE verified_at END WHERE id = ?`,
        )
        .run(
          JSON.stringify(contexts),
          options.confidence ?? 1.0,
          options.method ?? 'manual',
          options.verified ? 1 : 0,
          options.verifiedBy ?? null,
          options.verified ? 1 : 0,
          existing.id,
        );
    } else {
      const contexts = options.context ? [options.context] : [];
      this.db
        .prepare(
          `INSERT INTO entity_mentions (entity_id, document_id, mention_count, first_seen_at, last_seen_at, contexts_json, confidence_score, link_method, verified, verified_by, verified_at) VALUES (?, ?, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, ?, ?, ?, ?, ?, CASE WHEN ? THEN CURRENT_TIMESTAMP ELSE NULL END)`,
        )
        .run(
          entityId,
          documentId,
          JSON.stringify(contexts),
          options.confidence ?? 1.0,
          options.method ?? 'manual',
          options.verified ? 1 : 0,
          options.verifiedBy ?? null,
          options.verified ? 1 : 0,
        );
    }
    this.db
      .prepare(
        `UPDATE entities SET mentions = (SELECT COUNT(*) FROM entity_mentions WHERE entity_id = ?) WHERE id = ?`,
      )
      .run(entityId, entityId);
  }

  getPendingCandidates(limit = 50): EntityLinkCandidate[] {
    return this.db
      .prepare(
        `SELECT document_id as documentId, mention_text as mentionText, mention_context as mentionContext, start_offset as startOffset, end_offset as endOffset, candidate_entity_id as candidateEntityId, confidence_score as confidenceScore, match_method as matchMethod FROM entity_link_candidates WHERE processed = 0 AND accepted = 0 AND rejected = 0 ORDER BY confidence_score DESC, created_at ASC LIMIT ?`,
      )
      .all(limit) as EntityLinkCandidate[];
  }

  acceptCandidate(candidateId: number, userId?: number): void {
    const candidate = this.db
      .prepare(
        `SELECT document_id, candidate_entity_id, mention_context, confidence_score, match_method FROM entity_link_candidates WHERE id = ?`,
      )
      .get(candidateId) as
      | {
          document_id: number;
          candidate_entity_id: number;
          mention_context: string;
          confidence_score: number;
          match_method: string;
        }
      | undefined;
    if (!candidate) throw new Error(`Candidate ${candidateId} not found`);
    this.db
      .prepare(
        `UPDATE entity_link_candidates SET processed = 1, accepted = 1, reviewed_by = ?, reviewed_at = CURRENT_TIMESTAMP WHERE id = ?`,
      )
      .run(userId ?? null, candidateId);
    this.createEntityMention(candidate.document_id, candidate.candidate_entity_id, {
      confidence: candidate.confidence_score,
      method: candidate.match_method,
      context: candidate.mention_context,
      verified: true,
      verifiedBy: userId,
    });
  }

  rejectCandidate(candidateId: number, userId?: number, reason?: string): void {
    this.db
      .prepare(
        `UPDATE entity_link_candidates SET processed = 1, rejected = 1, reviewed_by = ?, reviewed_at = CURRENT_TIMESTAMP, notes = ? WHERE id = ?`,
      )
      .run(userId ?? null, reason ?? null, candidateId);
  }
}

/**
 * ResourcePreloader Utility
 *
 * Provides methods to pre-fetch data and assets to improve perceived performance.
 */

type PreloadPriority = 'high' | 'low';

interface PreloadOptions {
  priority?: PreloadPriority;
  timeout?: number;
}

class ResourcePreloader {
  private preloadedUrls = new Set<string>();
  private cache = new Map<string, any>();

  /**
   * Pre-fetches a JSON resource and caches it
   */
  async prefetchJson(url: string, options: PreloadOptions = {}) {
    if (this.preloadedUrls.has(url)) return;

    this.preloadedUrls.add(url);

    try {
      const response = await fetch(url);
      if (response.ok) {
        const data = await response.json();
        this.cache.set(url, data);
        console.log(`[Preloader] Prefetched JSON: ${url}`);
      }
    } catch (error) {
      console.warn(`[Preloader] Failed to prefetch JSON: ${url}`, error);
      this.preloadedUrls.delete(url);
    }
  }

  /**
   * Pre-fetches an image by creating a hidden Image object
   */
  prefetchImage(url: string) {
    if (this.preloadedUrls.has(url)) return;

    this.preloadedUrls.add(url);

    const img = new Image();
    img.src = url;
    img.onload = () => console.log(`[Preloader] Prefetched Image: ${url}`);
    img.onerror = () => this.preloadedUrls.delete(url);
  }

  /**
   * Gets a cached resource if available
   */
  getCached(url: string) {
    return this.cache.get(url);
  }

  /**
   * Clears the cache
   */
  clearCache() {
    this.cache.clear();
    this.preloadedUrls.clear();
  }
}

export const preloader = new ResourcePreloader();
export default preloader;

import { Entity, Relationship } from '../components/entities/EntityRelationshipMapper';
import { Investigation, EvidenceItem } from '../types/investigation';

// Types for raw data input (mocking what we might get from the API/DB)
export interface RawPerson {
  id: string;
  name: string;
  role?: string;
  affiliations?: string[];
  documents?: string[]; // IDs of documents they appear in
}

export interface RawDocument {
  id: string;
  title: string;
  date?: string;
  mentionedEntities?: string[]; // IDs of people mentioned
}

/**
 * Transforms raw application data into a network graph format
 */
export const transformToNetwork = (
  people: RawPerson[],
  documents: RawDocument[],
  investigation?: Investigation,
): { entities: Entity[]; relationships: Relationship[] } => {
  const entities: Entity[] = [];
  const relationships: Relationship[] = [];
  const entityMap = new Map<string, Entity>();

  // 1. Create Person Entities
  people.forEach((person) => {
    const entity: Entity = {
      id: person.id,
      type: 'person',
      label: person.name,
      properties: {
        role: person.role,
        affiliations: person.affiliations,
      },
      confidence: 1.0, // Base confidence
      sources: [], // To be populated
    };
    entities.push(entity);
    entityMap.set(person.id, entity);
  });

  // 2. Create Document Entities
  documents.forEach((doc) => {
    const entity: Entity = {
      id: doc.id,
      type: 'document',
      label: doc.title,
      properties: {
        date: doc.date,
      },
      confidence: 1.0,
      sources: [],
    };
    entities.push(entity);
    entityMap.set(doc.id, entity);
  });

  // 3. Create Relationships (Person -> Document)
  documents.forEach((doc) => {
    if (doc.mentionedEntities) {
      doc.mentionedEntities.forEach((personId) => {
        if (entityMap.has(personId)) {
          relationships.push({
            id: `rel-${doc.id}-${personId}`,
            from: personId,
            to: doc.id,
            type: 'appears_in',
            strength: 1,
            confidence: 0.9,
            evidence: [doc.id],
            properties: {},
          });
        }
      });
    }
  });

  // 4. Infer Person -> Person Relationships (Co-occurrence)
  // If two people appear in the same document, create a link
  const coOccurrenceMap = new Map<string, { count: number; docs: string[] }>();

  documents.forEach((doc) => {
    const mentioned = doc.mentionedEntities || [];
    for (let i = 0; i < mentioned.length; i++) {
      for (let j = i + 1; j < mentioned.length; j++) {
        const p1 = mentioned[i];
        const p2 = mentioned[j];
        // Sort IDs to ensure consistent key
        const key = [p1, p2].sort().join('-');

        if (!coOccurrenceMap.has(key)) {
          coOccurrenceMap.set(key, { count: 0, docs: [] });
        }
        const entry = coOccurrenceMap.get(key)!;
        entry.count++;
        entry.docs.push(doc.id);
      }
    }
  });

  coOccurrenceMap.forEach((value, key) => {
    const [p1, p2] = key.split('-');
    if (entityMap.has(p1) && entityMap.has(p2)) {
      relationships.push({
        id: `rel-${p1}-${p2}`,
        from: p1,
        to: p2,
        type: 'co_occurrence',
        strength: Math.min(value.count, 5), // Cap strength visually
        confidence: 0.8 + value.count * 0.05, // Increase confidence with more co-occurrences
        evidence: value.docs,
        properties: {
          sharedDocuments: value.count,
        },
      });
    }
  });

  return { entities, relationships };
};

